"use client"

import { useState, useEffect } from "react"
import { ArrowLeft, Save, Trash2, FileText, Image as ImageIcon } from "lucide-react"
import Link from "next/link"
import { useRouter, useParams } from "next/navigation"
import ImageUploader from "@/components/admin/ImageUploader"
import RichTextEditor from "@/components/admin/RichTextEditor"

export default function EditBlogPostPage() {
    const router = useRouter()
    const params = useParams()
    const { id } = params

    const [loading, setLoading] = useState(true)
    const [saving, setSaving] = useState(false)
    const [deleting, setDeleting] = useState(false)
    const [formData, setFormData] = useState<any>({
        title: "",
        category: "Teknoloji",
        image: "",
        excerpt: "",
        content: ""
    })

    useEffect(() => {
        const fetchData = async () => {
            try {
                const res = await fetch('/api/posts')
                const data = await res.json()
                const postsArray = Array.isArray(data) ? data : []
                const post = postsArray.find((item: any) => item.id == id)
                if (post) {
                    setFormData(post)
                } else {
                    alert("Yazı bulunamadı!")
                    router.push('/admin/blog')
                }
            } catch (error) {
                console.error("Veri hatası:", error)
            } finally {
                setLoading(false)
            }
        }
        fetchData()
    }, [id, router])

    const handleUpdate = async (e: React.FormEvent) => {
        e.preventDefault()
        setSaving(true)
        try {
            const res = await fetch('/api/posts', {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(formData),
            })
            if (!res.ok) throw new Error('Güncellenemedi')
            alert("Yazı güncellendi!")
            router.push('/admin/blog')
            router.refresh()
        } catch (error) {
            alert("Hata oluştu")
        } finally {
            setSaving(false)
        }
    }

    const handleDelete = async () => {
        if (!confirm("Bu yazıyı silmek istediğinize emin misiniz?")) return
        setDeleting(true)
        try {
            const res = await fetch(`/api/posts?id=${id}`, { method: 'DELETE' })
            if (!res.ok) throw new Error('Silinemedi')
            alert("Yazı silindi.")
            router.push('/admin/blog')
            router.refresh()
        } catch (error) {
            alert("Silme hatası")
        } finally {
            setDeleting(false)
        }
    }

    if (loading) return <div className="p-8 text-foreground">Yükleniyor...</div>

    return (
        <div className="p-8 max-w-5xl mx-auto space-y-8">
            <div className="flex justify-between items-center sticky top-0 py-4 bg-background/80 backdrop-blur z-20 border-b border-border">
                <div className="flex items-center gap-4">
                    <Link href="/admin/blog" className="p-2 hover:bg-muted rounded-lg text-muted-foreground hover:text-foreground"><ArrowLeft className="w-5 h-5" /></Link>
                    <h1 className="text-2xl font-bold text-foreground">Yazıyı Düzenle</h1>
                </div>
                <div className="flex gap-3">
                    <button onClick={handleDelete} disabled={deleting} className="px-4 py-2 bg-red-500/10 text-red-500 rounded-xl hover:bg-red-500/20 font-bold flex gap-2 items-center"><Trash2 className="w-4 h-4" /> Sil</button>
                    <button onClick={handleUpdate} disabled={saving} className="px-6 py-2 bg-emerald-500 text-white rounded-xl hover:bg-emerald-600 font-bold shadow-lg shadow-emerald-500/20 flex gap-2 items-center"><Save className="w-4 h-4" /> Kaydet</button>
                </div>
            </div>

            <div className="grid lg:grid-cols-2 gap-8">
                <div className="space-y-6">
                    <div className="bg-card border border-border rounded-notebook p-6 space-y-4">
                        <label className="text-muted-foreground text-sm font-bold">Başlık</label>
                        <input type="text" className="w-full bg-background border border-border rounded-xl px-4 py-3 text-foreground focus:outline-emerald-500" value={formData.title} onChange={e => setFormData({ ...formData, title: e.target.value })} />

                        <label className="text-muted-foreground text-sm font-bold">Kategori</label>
                        <select className="w-full bg-background border border-border rounded-xl px-4 py-3 text-foreground focus:outline-emerald-500" value={formData.category} onChange={e => setFormData({ ...formData, category: e.target.value })}>
                            {["Teknoloji", "Tasarım", "Yazılım", "Pazarlama", "SEO", "E-Ticaret"].map(c => <option key={c} value={c}>{c}</option>)}
                        </select>
                    </div>
                    <div className="bg-card border border-border rounded-notebook p-6 space-y-4">
                        <label className="text-muted-foreground text-sm font-bold">Kısa Özet</label>
                        <textarea className="w-full bg-background border border-border rounded-xl px-4 py-3 text-foreground focus:outline-emerald-500 h-32" value={formData.excerpt} onChange={e => setFormData({ ...formData, excerpt: e.target.value })} />
                    </div>
                </div>
                <div className="space-y-6">
                    <div className="bg-card border border-border rounded-notebook p-6 space-y-4">
                        <label className="text-muted-foreground text-sm font-bold">Görsel URL</label>
                        <ImageUploader
                            value={formData.image}
                            onChange={(url) => setFormData({ ...formData, image: url })}
                        />
                    </div>
                    <div className="bg-card border border-border rounded-notebook p-6 space-y-4">
                        <label className="text-muted-foreground text-sm font-bold">İçerik</label>
                        <RichTextEditor
                            content={formData.content}
                            onChange={(html) => setFormData({ ...formData, content: html })}
                        />
                    </div>
                </div>
            </div>
        </div>
    )
}

"use client"

import { useState, useEffect } from "react"
import {
    DndContext,
    closestCenter,
    KeyboardSensor,
    PointerSensor,
    useSensor,
    useSensors,
    DragEndEvent,
} from "@dnd-kit/core"
import {
    arrayMove,
    SortableContext,
    sortableKeyboardCoordinates,
    verticalListSortingStrategy,
    useSortable,
} from "@dnd-kit/sortable"
import { CSS } from "@dnd-kit/utilities"
import { GripVertical, Save, ArrowLeft, Loader2 } from "lucide-react"
import Link from "next/link"
import { useRouter } from "next/navigation"

interface Client {
    id: number
    name: string
    company?: string
    logo_url?: string
    order: number
}

function SortableItem({ id, client }: { id: number; client: Client }) {
    const {
        attributes,
        listeners,
        setNodeRef,
        transform,
        transition,
    } = useSortable({ id })

    const style = {
        transform: CSS.Transform.toString(transform),
        transition,
    }

    return (
        <div
            ref={setNodeRef}
            style={style}
            className="flex items-center gap-4 p-4 bg-card border border-border rounded-xl mb-3 shadow-sm group hover:border-emerald-500/30 transition-colors"
        >
            <div
                {...attributes}
                {...listeners}
                className="cursor-grab active:cursor-grabbing p-2 text-slate-500 hover:text-emerald-500 hover:bg-emerald-500/10 rounded-lg transition-colors"
            >
                <GripVertical className="w-5 h-5" />
            </div>

            <div className="w-10 h-10 bg-slate-800 rounded-lg border border-slate-700 flex items-center justify-center overflow-hidden shrink-0">
                {client.logo_url ? (
                    <img src={client.logo_url} alt={client.name} className="w-full h-full object-contain p-1" />
                ) : (
                    <span className="text-xs font-bold text-slate-500">
                        {client.name.substring(0, 2).toUpperCase()}
                    </span>
                )}
            </div>

            <div className="flex-1 min-w-0">
                <h3 className="font-medium text-foreground truncate">{client.name}</h3>
                {client.company && (
                    <p className="text-sm text-muted-foreground truncate">{client.company}</p>
                )}
            </div>
        </div>
    )
}

export default function ReorderClientsPage() {
    const [clients, setClients] = useState<Client[]>([])
    const [loading, setLoading] = useState(true)
    const [saving, setSaving] = useState(false)
    const router = useRouter()

    const sensors = useSensors(
        useSensor(PointerSensor),
        useSensor(KeyboardSensor, {
            coordinateGetter: sortableKeyboardCoordinates,
        })
    )

    useEffect(() => {
        fetchClients()
    }, [])

    const fetchClients = async () => {
        try {
            const res = await fetch('/api/clients')
            if (!res.ok) throw new Error('Failed to fetch')
            const data = await res.json()

            // Filter only active clients and sort by order
            const activeClients = Array.isArray(data)
                ? data.filter((c: any) => c.status === 'active')
                    .sort((a: any, b: any) => (a.order || 0) - (b.order || 0))
                : []

            setClients(activeClients)
        } catch (error) {
            console.error('Error fetching clients:', error)
        } finally {
            setLoading(false)
        }
    }

    const handleDragEnd = (event: DragEndEvent) => {
        const { active, over } = event

        if (over && active.id !== over.id) {
            setClients((items) => {
                const oldIndex = items.findIndex((item) => item.id === active.id)
                const newIndex = items.findIndex((item) => item.id === over.id)

                return arrayMove(items, oldIndex, newIndex)
            })
        }
    }

    const handleSave = async () => {
        setSaving(true)
        try {
            // Prepare data with new order indices
            const updates = clients.map((client, index) => ({
                id: client.id,
                order: index + 1
            }))

            const res = await fetch('/api/admin/clients/reorder', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ items: updates }),
            })

            if (!res.ok) throw new Error('Failed to save order')

            router.refresh()
            // Optional: Show success toast/alert
            alert('Sıralama başarıyla kaydedildi')
        } catch (error) {
            console.error('Error saving order:', error)
            alert('Kaydederken bir hata oluştu')
        } finally {
            setSaving(false)
        }
    }

    if (loading) {
        return (
            <div className="flex items-center justify-center min-h-[400px]">
                <Loader2 className="w-8 h-8 animate-spin text-emerald-500" />
            </div>
        )
    }

    return (
        <div className="p-8 max-w-4xl mx-auto">
            {/* Header */}
            <div className="flex items-center justify-between mb-8">
                <div className="flex items-center gap-4">
                    <Link
                        href="/admin/clients"
                        className="p-2 hover:bg-slate-800 rounded-lg transition-colors text-slate-400 hover:text-white"
                    >
                        <ArrowLeft className="w-5 h-5" />
                    </Link>
                    <div>
                        <h1 className="text-2xl font-bold text-foreground">Marka Sıralaması</h1>
                        <p className="text-muted-foreground">Sürükle bırak ile markaların sırasını düzenleyin</p>
                    </div>
                </div>

                <button
                    onClick={handleSave}
                    disabled={saving}
                    className="flex items-center gap-2 px-6 py-2.5 bg-emerald-500 hover:bg-emerald-600 text-white rounded-xl font-bold transition-all shadow-lg shadow-emerald-500/20 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                    {saving ? (
                        <>
                            <Loader2 className="w-4 h-4 animate-spin" />
                            Kaydediliyor...
                        </>
                    ) : (
                        <>
                            <Save className="w-4 h-4" />
                            Kaydet
                        </>
                    )}
                </button>
            </div>

            {/* Sortable List */}
            <DndContext
                sensors={sensors}
                collisionDetection={closestCenter}
                onDragEnd={handleDragEnd}
            >
                <SortableContext
                    items={clients.map(c => c.id)}
                    strategy={verticalListSortingStrategy}
                >
                    <div className="space-y-3">
                        {clients.map((client) => (
                            <SortableItem key={client.id} id={client.id} client={client} />
                        ))}
                    </div>
                </SortableContext>
            </DndContext>

            {clients.length === 0 && (
                <div className="text-center py-12 text-muted-foreground bg-card border border-border rounded-xl">
                    Sıralanacak aktif marka bulunamadı.
                </div>
            )}
        </div>
    )
}

"use client"

export const dynamic = "force-dynamic"

import { useEffect, useState } from "react"
import { Users, Plus, Search, Mail, Phone, Building2, ExternalLink, Pencil, Trash2 } from "lucide-react"
import Link from "next/link"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Card, CardContent } from "@/components/ui/card"

interface Client {
    id: number
    name: string
    company: string
    email: string
    phone: string
    status: string
    total_revenue: number
    created_at: string
}

export default function ClientsPage() {
    const [clients, setClients] = useState<Client[]>([])
    const [loading, setLoading] = useState(true)
    const [searchTerm, setSearchTerm] = useState("")

    useEffect(() => {
        fetchClients()
    }, [])

    const fetchClients = async () => {
        try {
            const res = await fetch('/api/clients')
            const data = await res.json()

            if (Array.isArray(data) && data.length > 0) {
                setClients(data)
            } else if (process.env.NODE_ENV === 'development') {
                console.log("⚠️ Dev Mode: Using Mock Clients")
                const mocks = require('@/lib/mock-data').MOCK_CLIENTS
                setClients(mocks)
            } else {
                setClients([])
            }
        } catch (error) {
            console.error('Fetch error:', error)
            if (process.env.NODE_ENV === 'development') {
                setClients(require('@/lib/mock-data').MOCK_CLIENTS)
            } else {
                setClients([])
            }
        } finally {
            setLoading(false)
        }
    }

    const handleDelete = async (id: number) => {
        if (!confirm('Bu müşteriyi silmek istediğinize emin misiniz?')) return

        try {
            const res = await fetch(`/api/clients?id=${id}`, { method: 'DELETE' })
            if (res.ok) {
                setClients(clients.filter(c => c.id !== id))
                alert('Müşteri silindi')
            }
        } catch (error) {
            alert('Silme hatası')
        }
    }

    const filteredClients = clients.filter(client =>
        client.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        client.company?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        client.email?.toLowerCase().includes(searchTerm.toLowerCase())
    )

    const getStatusColor = (status: string) => {
        switch (status) {
            case 'active': return 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20'
            case 'potential': return 'bg-blue-500/10 text-blue-400 border-blue-500/20'
            case 'inactive': return 'bg-slate-700/50 text-muted-foreground border-border'
            default: return 'bg-slate-700/50 text-muted-foreground'
        }
    }

    const getStatusText = (status: string) => {
        switch (status) {
            case 'active': return 'Aktif'
            case 'potential': return 'Potansiyel'
            case 'inactive': return 'Pasif'
            default: return status
        }
    }

    if (loading) {
        return (
            <div className="p-8">
                <div className="text-muted-foreground">Yükleniyor...</div>
            </div>
        )
    }

    return (
        <div className="p-8 max-w-7xl mx-auto space-y-8">

            {/* Header */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h1 className="text-3xl font-bold text-foreground flex items-center gap-3">
                        <Users className="w-8 h-8 text-emerald-500" />
                        Müşteriler
                    </h1>
                    <p className="text-muted-foreground mt-1">Müşteri ilişkilerinizi yönetin</p>
                </div>
                <Link href="/admin/clients/new">
                    <Button className="w-fit" size="lg">
                        <Plus className="w-5 h-5 mr-2" />
                        Yeni Müşteri
                    </Button>
                </Link>
            </div>

            {/* Search */}
            <div className="relative">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-muted-foreground" />
                <Input
                    type="text"
                    placeholder="Müşteri ara (isim, şirket, email)..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-12 py-6 text-base rounded-xl"
                />
            </div>

            {/* Stats */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <Card>
                    <CardContent className="p-4">
                        <p className="text-muted-foreground text-sm">Toplam Müşteri</p>
                        <p className="text-2xl font-bold text-foreground mt-1">{clients.length}</p>
                    </CardContent>
                </Card>
                <Card>
                    <CardContent className="p-4">
                        <p className="text-muted-foreground text-sm">Aktif Müşteri</p>
                        <p className="text-2xl font-bold text-emerald-400 mt-1">
                            {clients.filter(c => c.status === 'active').length}
                        </p>
                    </CardContent>
                </Card>
                <Card>
                    <CardContent className="p-4">
                        <p className="text-muted-foreground text-sm">Potansiyel</p>
                        <p className="text-2xl font-bold text-blue-400 mt-1">
                            {clients.filter(c => c.status === 'potential').length}
                        </p>
                    </CardContent>
                </Card>
            </div>

            {/* Clients List */}
            <Card className="rounded-xl overflow-hidden shadow-sm">
                {filteredClients.length === 0 ? (
                    <div className="p-12 text-center">
                        <Users className="w-16 h-16 text-slate-700 mx-auto mb-4" />
                        <p className="text-muted-foreground">
                            {searchTerm ? 'Müşteri bulunamadı' : 'Henüz müşteri eklenmemiş'}
                        </p>
                        {!searchTerm && (
                            <Link href="/admin/clients/new">
                                <Button className="mt-4">İlk Müşteriyi Ekle</Button>
                            </Link>
                        )}
                    </div>
                ) : (
                    <div className="divide-y divide-border">
                        {filteredClients.map((client) => (
                            <div key={client.id} className="p-6 hover:bg-muted/50 transition-colors">
                                <div className="flex items-start justify-between gap-4">
                                    <div className="flex-1">
                                        <div className="flex items-center gap-3 mb-2">
                                            <h3 className="text-lg font-bold text-foreground">{client.name}</h3>
                                            <span className={`text-xs px-2.5 py-1 rounded-md font-medium border ${getStatusColor(client.status)}`}>
                                                {getStatusText(client.status)}
                                            </span>
                                        </div>
                                        {client.company && (
                                            <div className="flex items-center gap-2 text-muted-foreground text-sm mb-1">
                                                <Building2 className="w-4 h-4" />
                                                {client.company}
                                            </div>
                                        )}
                                        <div className="flex flex-col md:flex-row md:items-center gap-2 md:gap-4 text-sm text-muted-foreground">
                                            {client.email && (
                                                <div className="flex items-center gap-2">
                                                    <Mail className="w-4 h-4" />
                                                    {client.email}
                                                </div>
                                            )}
                                            {client.phone && (
                                                <div className="flex items-center gap-2">
                                                    <Phone className="w-4 h-4" />
                                                    {client.phone}
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <Link href={`/admin/clients/${client.id}`}>
                                            <Button variant="ghost" size="icon" title="Düzenle">
                                                <Pencil className="w-4 h-4" />
                                            </Button>
                                        </Link>
                                        <Button
                                            variant="ghost"
                                            size="icon"
                                            onClick={() => handleDelete(client.id)}
                                            className="text-red-500 hover:text-red-400 hover:bg-red-500/10"
                                            title="Sil"
                                        >
                                            <Trash2 className="w-4 h-4" />
                                        </Button>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </Card>
        </div>
    )
}

"use client"

export const dynamic = "force-dynamic"

import { useState, useEffect, use } from "react"
import { ArrowLeft, Building2, Mail, Phone, MapPin, Calendar, Clock, DollarSign, Wallet } from "lucide-react"
import Link from "next/link"

export default function ClientDetailPage({ params }: { params: Promise<{ id: string }> }) {
    const { id } = use(params)
    const [data, setData] = useState<any>(null)
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        const fetchData = async () => {
            try {
                const res = await fetch(`/api/finance/clients/${id}`)
                const json = await res.json()
                setData(json)
            } catch (error) {
                console.error('Error:', error)
            } finally {
                setLoading(false)
            }
        }
        fetchData()
    }, [id])

    const formatCurrency = (amount: number) => {
        return new Intl.NumberFormat('tr-TR', { style: 'currency', currency: 'TRY' }).format(amount || 0)
    }

    if (loading) return <div className="p-12 text-center text-muted-foreground">Yükleniyor...</div>
    if (!data?.client) return <div className="p-12 text-center text-muted-foreground">Müşteri bulunamadı.</div>

    const { client, projects, incomes, transactions } = data

    return (
        <div className="p-8 max-w-7xl mx-auto space-y-8">
            <Link href="/admin/finance/clients" className="text-muted-foreground hover:text-foreground flex items-center gap-2 transition-colors">
                <ArrowLeft className="w-4 h-4" /> Cari Listesine Dön
            </Link>

            <div className="grid lg:grid-cols-3 gap-8">
                {/* Sol Kolon: Müşteri Bilgisi */}
                <div className="space-y-6">
                    <div className="bg-card border border-border p-6 rounded-notebook">
                        <div className="w-20 h-20 rounded-full bg-blue-500/10 text-blue-500 flex items-center justify-center text-3xl font-bold mb-4">
                            {client.name?.[0]?.toUpperCase()}
                        </div>
                        <h1 className="text-2xl font-bold text-foreground mb-2">{client.name}</h1>
                        <div className="space-y-3 text-sm text-muted-foreground">
                            {client.email && (
                                <div className="flex items-center gap-3">
                                    <Mail className="w-4 h-4" /> {client.email}
                                </div>
                            )}
                            {client.phone && (
                                <div className="flex items-center gap-3">
                                    <Phone className="w-4 h-4" /> {client.phone}
                                </div>
                            )}
                            {client.address && (
                                <div className="flex items-center gap-3">
                                    <MapPin className="w-4 h-4" /> {client.address}
                                </div>
                            )}
                            {client.company && (
                                <div className="flex items-center gap-3">
                                    <Building2 className="w-4 h-4" /> {client.company}
                                </div>
                            )}
                        </div>
                    </div>

                    <div className="bg-card border border-border p-6 rounded-notebook">
                        <h3 className="font-bold text-foreground mb-4">Finansal Özet</h3>
                        <div className="space-y-4">
                            {/* CSS FIX: bg-slate-800 yerine bg-muted/50 kullanıldı, border eklendi */}
                            <div className="flex justify-between items-center p-3 bg-muted/50 border border-border rounded-xl">
                                <span className="text-sm text-muted-foreground">Toplam Borç (Ciro)</span>
                                <span className="font-bold text-foreground">{formatCurrency(client.total_revenue)}</span>
                            </div>
                            <div className="flex justify-between items-center p-3 bg-muted/50 border border-border rounded-xl">
                                <span className="text-sm text-muted-foreground">Toplam Ödenen</span>
                                <span className="font-bold text-emerald-500">{formatCurrency(client.total_paid)}</span>
                            </div>
                            <div className="pt-2 border-t border-border mt-2">
                                <div className="flex justify-between items-center">
                                    <span className="text-sm font-bold text-foreground">Güncel Bakiye (Kalan)</span>
                                    <span className={`text-xl font-bold ${(client.balance || 0) > 0 ? 'text-amber-500' : 'text-emerald-500'}`}>
                                        {formatCurrency(client.balance)}
                                    </span>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Sağ Kolon: Detaylar */}
                <div className="lg:col-span-2 space-y-8">

                    {/* Transactions / Timeline */}
                    <div className="bg-card border border-border p-6 rounded-notebook">
                        <h2 className="text-xl font-bold text-foreground mb-6 flex items-center gap-2">
                            <Clock className="w-5 h-5 text-blue-500" />
                            İşlem Geçmişi
                        </h2>

                        <div className="space-y-6 relative pl-6 border-l-2 border-border ml-2">
                            {/* Eğer Transaction tablosu boşsa projelere ve ödemelere göre sanal bir timeline oluştur */}
                            {incomes?.map((inc: any) => (
                                <div key={inc.id} className="relative">
                                    <div className={`absolute -left-[31px] top-1 w-4 h-4 rounded-full border-4 border-card ${inc.status === 'pending' || !inc.is_paid ? 'bg-amber-500' : 'bg-emerald-500'}`}></div>
                                    <div className={`p-4 rounded-xl border ${inc.status === 'pending' || !inc.is_paid ? 'bg-amber-500/10 border-amber-500/20' : 'bg-emerald-500/10 border-emerald-500/20'}`}>
                                        <div className="flex justify-between items-start mb-1">
                                            <span className={`font-bold ${inc.status === 'pending' || !inc.is_paid ? 'text-amber-500' : 'text-emerald-500'}`}>
                                                {inc.status === 'pending' || !inc.is_paid ? 'Bekleyen Ödeme (Alacak)' : 'Tahsilat / Ödeme Alındı'}
                                            </span>
                                            <span className="text-xs text-muted-foreground">{new Date(inc.date).toLocaleDateString('tr-TR')}</span>
                                        </div>
                                        <p className="text-foreground font-medium">{inc.description || 'Ödeme Hareketi'}</p>
                                        <p className="text-lg font-bold text-foreground mt-1">{formatCurrency(inc.amount)}</p>
                                    </div>
                                </div>
                            ))}

                            {projects?.map((proj: any) => (
                                <div key={proj.id} className="relative">
                                    <div className="absolute -left-[31px] top-1 w-4 h-4 rounded-full bg-blue-500 border-4 border-card"></div>
                                    <div className="bg-blue-500/10 p-4 rounded-xl border border-blue-500/20">
                                        <div className="flex justify-between items-start mb-1">
                                            <span className="font-bold text-blue-500">Proje / Hizmet</span>
                                            <span className="text-xs text-muted-foreground">{new Date(proj.created_at).toLocaleDateString('tr-TR')}</span>
                                        </div>
                                        <p className="text-foreground font-medium">{proj.name}</p>
                                        <p className="text-sm text-muted-foreground mt-1">Durum: {proj.status}</p>
                                    </div>
                                </div>
                            ))}

                            {(!incomes?.length && !projects?.length) && (
                                <p className="text-muted-foreground italic">Henüz bir işlem kaydı yok.</p>
                            )}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    )
}

"use client"

export const dynamic = "force-dynamic"

import { useState, useEffect } from "react"
import { ArrowLeft, Save, TrendingDown, Trash2, Calendar } from "lucide-react"
import Link from "next/link"

export default function ExpensesPage() {
    const [loading, setLoading] = useState(false)
    const [expenses, setExpenses] = useState<any[]>([])
    const [members, setMembers] = useState<any[]>([])
    const [showForm, setShowForm] = useState(false)
    const [formData, setFormData] = useState({
        amount: "",
        date: new Date().toISOString().split('T')[0],
        category: "office",
        description: "",
        invoice_number: "",
        vendor: "",
        paid_by: "", // Yeni: Ödeyen kişi ID'si (boş = Kasa)
        is_recurring: false,
        recurrence_frequency: "monthly",
        recurrence_day: new Date().getDate(),
    })

    useEffect(() => {
        fetchExpenses()
        fetchMembers()
    }, [])

    const fetchMembers = async () => {
        try {
            const res = await fetch('/api/team')
            const data = await res.json()
            setMembers(data || [])
        } catch (error) {
            console.error('Members fetch error:', error)
        }
    }

    const fetchExpenses = async () => {
        try {
            const res = await fetch('/api/finance/expenses')
            const data = await res.json()
            setExpenses(data)
        } catch (error) {
            console.error('Fetch error:', error)
        }
    }

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()
        setLoading(true)

        try {
            const payload = {
                ...formData,
                amount: parseFloat(formData.amount),
                paid_by: formData.paid_by || null // Boşsa Kasa (null)
            }

            const res = await fetch('/api/finance/expenses', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload)
            })

            if (!res.ok) throw new Error('Eklenemedi')

            alert('Gider başarıyla eklendi!')
            setShowForm(false)
            setFormData({
                amount: "",
                date: new Date().toISOString().split('T')[0],
                category: "office",
                description: "",
                invoice_number: "",
                vendor: "",
                paid_by: "",
                is_recurring: false,
                recurrence_frequency: "monthly",
                recurrence_day: new Date().getDate(),
            })
            fetchExpenses()
        } catch (error) {
            alert('Bir hata oluştu!')
        } finally {
            setLoading(false)
        }
    }

    const handleDelete = async (id: number) => {
        if (!confirm('Bu gider kaydını silmek istediğinize emin misiniz?')) return

        try {
            const res = await fetch(`/api/finance/expenses?id=${id}`, { method: 'DELETE' })
            if (res.ok) {
                setExpenses(expenses.filter(e => e.id !== id))
                alert('Gider silindi')
            }
        } catch (error) {
            alert('Silme hatası')
        }
    }

    const formatCurrency = (amount: number) => {
        return new Intl.NumberFormat('tr-TR', { style: 'currency', currency: 'TRY', minimumFractionDigits: 0 }).format(amount)
    }

    const totalExpenses = expenses.reduce((sum, item) => sum + parseFloat(item.amount || 0), 0)
    const recurringExpenses = expenses.filter(e => e.is_recurring)

    const categoryLabels: any = {
        rent: 'Kira',
        salary: 'Maaş',
        software: 'Yazılım/Abonelik',
        ads: 'Reklam',
        office: 'Ofis Giderleri',
        other: 'Diğer'
    }

    return (
        <div className="p-8 max-w-7xl mx-auto space-y-8">

            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <Link
                        href="/admin/finance"
                        className="inline-flex items-center gap-2 text-slate-400 hover:text-foreground transition-colors mb-4"
                    >
                        <ArrowLeft className="w-4 h-4" />
                        Finans'a Dön
                    </Link>
                    <h1 className="text-3xl font-bold text-foreground flex items-center gap-3">
                        <TrendingDown className="w-8 h-8 text-red-500" />
                        Gider Yönetimi
                    </h1>
                    <p className="text-slate-400 mt-1">Masraflar ve düzenli ödemeleri kaydedin</p>
                </div>
                <button
                    onClick={() => setShowForm(!showForm)}
                    className="px-6 py-3 bg-red-500 hover:bg-red-600 text-white rounded-xl font-bold transition-all shadow-lg shadow-red-500/20"
                >
                    {showForm ? 'Formu Gizle' : '+ Yeni Gider'}
                </button>
            </div>

            {/* Stats */}
            <div className="grid md:grid-cols-3 gap-4">
                <div className="bg-card border border-border p-4 rounded-xl">
                    <p className="text-slate-400 text-sm">Toplam Gider</p>
                    <p className="text-2xl font-bold text-red-400 mt-1">{formatCurrency(totalExpenses)}</p>
                </div>
                <div className="bg-card border border-border p-4 rounded-xl">
                    <p className="text-slate-400 text-sm">Kayıt Sayısı</p>
                    <p className="text-2xl font-bold text-foreground mt-1">{expenses.length}</p>
                </div>
                <div className="bg-card border border-border p-4 rounded-xl">
                    <p className="text-slate-400 text-sm">Düzenli Gider</p>
                    <p className="text-2xl font-bold text-purple-400 mt-1">{recurringExpenses.length} kayıt</p>
                </div>
            </div>

            {/* Form */}
            {showForm && (
                <form onSubmit={handleSubmit} className="bg-card border border-border rounded-notebook p-6 space-y-6">
                    <h2 className="text-lg font-bold text-foreground border-b border-border pb-3">Yeni Gider Kaydı</h2>

                    <div className="grid md:grid-cols-2 gap-4">
                        <div>
                            <label className="block text-slate-400 text-sm font-medium mb-2">Tutar *</label>
                            <input
                                type="number"
                                required
                                step="0.01"
                                value={formData.amount}
                                onChange={(e) => setFormData({ ...formData, amount: e.target.value })}
                                className="w-full bg-background border border-border rounded-xl px-4 py-3 text-foreground focus:outline-none focus:border-red-500"
                                placeholder="0.00"
                            />
                        </div>

                        <div>
                            <label className="block text-slate-400 text-sm font-medium mb-2">Tarih *</label>
                            <input
                                type="date"
                                required
                                value={formData.date}
                                onChange={(e) => setFormData({ ...formData, date: e.target.value })}
                                className="w-full bg-background border border-border rounded-xl px-4 py-3 text-foreground focus:outline-none focus:border-red-500"
                            />
                        </div>

                        <div>
                            <label className="block text-slate-400 text-sm font-medium mb-2">Kategori *</label>
                            <select
                                required
                                value={formData.category}
                                onChange={(e) => setFormData({ ...formData, category: e.target.value })}
                                className="w-full bg-background border border-border rounded-xl px-4 py-3 text-foreground focus:outline-none focus:border-red-500"
                            >
                                <option value="rent">Kira</option>
                                <option value="salary">Maaş</option>
                                <option value="software">Yazılım/Abonelik</option>
                                <option value="ads">Reklam</option>
                                <option value="office">Ofis Giderleri</option>
                                <option value="other">Diğer</option>
                            </select>
                        </div>

                        <div>
                            <label className="block text-slate-400 text-sm font-medium mb-2">Ödeme Yapan (Kim Ödedi?)</label>
                            <select
                                value={formData.paid_by}
                                onChange={(e) => setFormData({ ...formData, paid_by: e.target.value })}
                                className="w-full bg-background border border-border rounded-xl px-4 py-3 text-foreground focus:outline-none focus:border-red-500"
                            >
                                <option value="">Şirket Kasası / Banka</option>
                                {members.map(member => (
                                    <option key={member.id} value={member.id}>
                                        {member.name} (Ortak/Personel)
                                    </option>
                                ))}
                            </select>
                            <p className="text-xs text-slate-500 mt-1">Seçilmezse şirket kasasından düşer.</p>
                        </div>

                        <div>
                            <label className="block text-slate-400 text-sm font-medium mb-2">Firma/Tedarikçi</label>
                            <input
                                type="text"
                                value={formData.vendor}
                                onChange={(e) => setFormData({ ...formData, vendor: e.target.value })}
                                className="w-full bg-background border border-border rounded-xl px-4 py-3 text-foreground focus:outline-none focus:border-red-500"
                                placeholder="Örneğin: AWS, Google Ads..."
                            />
                        </div>

                        <div>
                            <label className="block text-slate-400 text-sm font-medium mb-2">Fatura No</label>
                            <input
                                type="text"
                                value={formData.invoice_number}
                                onChange={(e) => setFormData({ ...formData, invoice_number: e.target.value })}
                                className="w-full bg-background border border-border rounded-xl px-4 py-3 text-foreground focus:outline-none focus:border-red-500"
                                placeholder="FT-2024-001"
                            />
                        </div>

                        <div>
                            <label className="block text-slate-400 text-sm font-medium mb-2">Açıklama</label>
                            <input
                                type="text"
                                value={formData.description}
                                onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                                className="w-full bg-background border border-border rounded-xl px-4 py-3 text-foreground focus:outline-none focus:border-red-500"
                                placeholder="Ocak ayı ofis kirası"
                            />
                        </div>
                    </div>

                    {/* Recurring Section */}
                    <div className="border-t border-border pt-4">
                        <label className="flex items-center gap-3 cursor-pointer">
                            <input
                                type="checkbox"
                                checked={formData.is_recurring}
                                onChange={(e) => setFormData({ ...formData, is_recurring: e.target.checked })}
                                className="w-5 h-5 bg-background border-border rounded text-red-500 focus:ring-red-500"
                            />
                            <div>
                                <span className="text-foreground font-medium flex items-center gap-2">
                                    <Calendar className="w-4 h-4 text-purple-400" />
                                    Düzenli Gider (Aylık tekrar eden)
                                </span>
                                <p className="text-slate-400 text-xs mt-1">Bu gider her ay otomatik olarak tekrarlanacak</p>
                            </div>
                        </label>

                        {formData.is_recurring && (
                            <div className="mt-4 grid md:grid-cols-2 gap-4 pl-8">
                                <div>
                                    <label className="block text-slate-400 text-sm font-medium mb-2">Tekrar Sıklığı</label>
                                    <select
                                        value={formData.recurrence_frequency}
                                        onChange={(e) => setFormData({ ...formData, recurrence_frequency: e.target.value })}
                                        className="w-full bg-background border border-border rounded-xl px-4 py-3 text-foreground focus:outline-none focus:border-red-500"
                                    >
                                        <option value="monthly">Aylık</option>
                                        <option value="quarterly">3 Ayda Bir</option>
                                        <option value="yearly">Yıllık</option>
                                    </select>
                                </div>
                                <div>
                                    <label className="block text-slate-400 text-sm font-medium mb-2">Ayın Hangi Günü</label>
                                    <input
                                        type="number"
                                        min="1"
                                        max="31"
                                        value={formData.recurrence_day}
                                        onChange={(e) => setFormData({ ...formData, recurrence_day: parseInt(e.target.value) })}
                                        className="w-full bg-background border border-border rounded-xl px-4 py-3 text-foreground focus:outline-none focus:border-red-500"
                                    />
                                </div>
                            </div>
                        )}
                    </div>

                    <div className="flex gap-4">
                        <button
                            type="submit"
                            disabled={loading}
                            className="flex-1 px-6 py-3 bg-red-500 hover:bg-red-600 disabled:opacity-50 text-white rounded-xl font-bold transition-all shadow-lg shadow-red-500/20 flex items-center justify-center gap-2"
                        >
                            <Save className="w-5 h-5" />
                            {loading ? 'Kaydediliyor...' : 'Gideri Kaydet'}
                        </button>
                    </div>
                </form>
            )}

            {/* Expenses List */}
            <div className="bg-card border border-border rounded-notebook overflow-hidden">
                <div className="p-4 border-b border-border">
                    <h3 className="text-lg font-bold text-foreground">Gider Kayıtları</h3>
                </div>
                {expenses.length === 0 ? (
                    <div className="p-12 text-center text-slate-400">
                        Henüz gider kaydı yok
                    </div>
                ) : (
                    <div className="divide-y divide-slate-800">
                        {expenses.map((item) => (
                            <div key={item.id} className="p-4 hover:bg-slate-800/50 transition-colors flex items-center justify-between">
                                <div className="flex-1">
                                    <div className="flex items-center gap-3 mb-1">
                                        <h4 className="text-foreground font-medium">
                                            {item.description || categoryLabels[item.category]}
                                        </h4>
                                        <span className="text-xs px-2 py-1 bg-muted text-slate-400 rounded-md">
                                            {categoryLabels[item.category]}
                                        </span>
                                        {item.team_members && (
                                            <span className="text-xs px-2 py-1 bg-blue-500/10 text-blue-400 rounded-md border border-blue-500/20">
                                                Ödeyen: {item.team_members.name}
                                            </span>
                                        )}
                                        {item.is_recurring && (
                                            <span className="text-xs px-2 py-1 bg-purple-500/10 text-purple-400 rounded-md border border-purple-500/20 flex items-center gap-1">
                                                <Calendar className="w-3 h-3" />
                                                Düzenli
                                            </span>
                                        )}
                                    </div>
                                    <p className="text-slate-400 text-sm">
                                        {new Date(item.date).toLocaleDateString('tr-TR')}
                                        {item.vendor && ` • ${item.vendor}`}
                                        {item.invoice_number && ` • ${item.invoice_number}`}
                                    </p>
                                </div>
                                <div className="flex items-center gap-4">
                                    <p className="text-red-400 font-bold text-lg">{formatCurrency(item.amount)}</p>
                                    <button
                                        onClick={() => handleDelete(item.id)}
                                        className="p-2 bg-red-500/10 hover:bg-red-500/20 rounded-lg text-red-400 transition-colors"
                                    >
                                        <Trash2 className="w-4 h-4" />
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </div>
    )
}

"use client"

import { useEffect, useState } from "react"
import { useParams, useRouter } from "next/navigation"
import LabProjectForm from "@/components/admin/lab/LabProjectForm"
import { LabProjectFormData } from "@/types/lab"

export default function EditLabProjectPage() {
    const params = useParams()
    const router = useRouter()
    const [project, setProject] = useState<Partial<LabProjectFormData> | null>(null)
    const [submitting, setSubmitting] = useState(false)

    useEffect(() => {
        fetch(`/api/projects?id=${params.id}`)
            .then(res => res.json())
            .then(data => {
                if (data.error) throw new Error(data.error)
                setProject(data)
            })
            .catch(() => {
                alert('Proje yüklenemedi')
                router.push('/admin/laboratuvar')
            })
    }, [params.id]) // Correct dependency

    const handleSubmit = async (data: LabProjectFormData) => {
        setSubmitting(true)
        try {
            const res = await fetch('/api/projects', {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ id: params.id, ...data })
            })

            if (!res.ok) throw new Error('Failed')

            alert('Proje başarıyla güncellendi!')
            router.push('/admin/laboratuvar')
        } catch (error) {
            console.error(error)
            alert('Hata oluştu')
        } finally {
            setSubmitting(false)
        }
    }

    if (!project) return <div className="p-20 text-center">Yükleniyor...</div>

    return (
        <div className="p-8">
            <h1 className="text-3xl font-bold mb-8">Projeyi Düzenle</h1>
            <LabProjectForm initialData={project} onSubmit={handleSubmit} loading={submitting} />
        </div>
    )
}

"use client"

import { useEffect, useState } from "react"
import { Briefcase, Plus, Save, LayoutGrid, List as ListIcon, Trash2, MoreHorizontal, GripVertical } from "lucide-react"
import Link from "next/link"
import { cn } from "@/lib/utils"
import {
    DndContext,
    closestCenter,
    KeyboardSensor,
    PointerSensor,
    useSensor,
    useSensors,
    DragEndEvent
} from '@dnd-kit/core';
import {
    arrayMove,
    SortableContext,
    sortableKeyboardCoordinates,
    verticalListSortingStrategy,
    useSortable
} from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';

// Interface
interface LabProject {
    id: number
    internalName?: string
    publicTitle?: string
    name?: string
    thumbnail?: string
    liveUrl?: string
    status: string
    order: number
    tags: string[]
}

// Sortable Item
function SortableLabProject({ project, viewMode, handleDelete }: any) {
    const {
        attributes,
        listeners,
        setNodeRef,
        transform,
        transition,
        isDragging
    } = useSortable({ id: project.id });

    const style = {
        transform: CSS.Transform.toString(transform),
        transition,
        zIndex: isDragging ? 10 : 1,
        opacity: isDragging ? 0.5 : 1,
    };

    if (viewMode === 'grid') {
        return (
            <div
                ref={setNodeRef}
                style={style}
                className="group relative bg-card border border-border rounded-3xl p-4 transition-all hover:border-emerald-500/30 hover:shadow-xl flex flex-col h-full overflow-hidden"
            >
                {/* Drag Handle */}
                <div className="absolute top-4 right-4 z-20 cursor-grab active:cursor-grabbing p-2 bg-black/20 hover:bg-black/40 text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity" {...attributes} {...listeners}>
                    <GripVertical className="w-4 h-4" />
                </div>

                {/* Thumbnail */}
                <div className="relative aspect-video rounded-2xl bg-muted overflow-hidden mb-4 border border-border/50">
                    {project.thumbnail ? (
                        <img src={project.thumbnail} alt={project.publicTitle} className="w-full h-full object-cover" />
                    ) : (
                        <div className="w-full h-full flex items-center justify-center text-muted-foreground bg-muted">
                            <Briefcase className="w-8 h-8 opacity-20" />
                        </div>
                    )}
                </div>

                <div className="flex-1 space-y-2">
                    {/* Internal Name */}
                    <div className="text-xs text-emerald-500 font-bold uppercase tracking-wider">
                        {project.internalName || 'İsimsiz'}
                    </div>
                    {/* Public Title */}
                    <h3 className="text-lg font-bold text-foreground line-clamp-1">
                        {project.publicTitle || project.name || '-'}
                    </h3>

                    {/* URL */}
                    {project.liveUrl && (
                        <a href={project.liveUrl} target="_blank" className="text-xs text-blue-500 hover:underline block truncate">
                            {project.liveUrl}
                        </a>
                    )}

                    {/* Tags */}
                    <div className="flex flex-wrap gap-1 mt-2">
                        {project.tags && project.tags.slice(0, 3).map((tag: string) => (
                            <span key={tag} className="px-1.5 py-0.5 bg-muted rounded text-[10px] text-muted-foreground border border-border">
                                {tag}
                            </span>
                        ))}
                    </div>
                </div>

                {/* Actions */}
                <div className="mt-4 pt-4 border-t border-border flex justify-between items-center">
                    <Link
                        href={`/admin/laboratuvar/edit/${project.id}`}
                        className="text-sm font-medium text-emerald-500 hover:text-emerald-400 transition-colors"
                    >
                        Düzenle
                    </Link>
                    <button
                        onClick={() => handleDelete(project.id)}
                        className="p-1.5 hover:bg-red-500/10 text-muted-foreground hover:text-red-500 rounded transition-colors"
                    >
                        <Trash2 className="w-4 h-4" />
                    </button>
                </div>
            </div>
        )
    }

    // List View
    return (
        <tr ref={setNodeRef} style={style} className="group hover:bg-muted/30 transition-colors bg-card">
            <td className="p-4 w-10">
