            <td className="p-4 text-muted-foreground text-sm truncate max-w-[200px]">
                {project.liveUrl || '-'}
            </td>
            <td className="p-4 text-right">
                <div className="flex items-center justify-end gap-2">
                    <Link
                        href={`/admin/laboratuvar/edit/${project.id}`}
                        className="p-2 hover:bg-muted rounded-lg text-emerald-500 transition-colors"
                    >
                        Düzenle
                    </Link>
                    <button
                        onClick={() => handleDelete(project.id)}
                        className="p-2 hover:bg-red-500/10 rounded-lg text-red-500 transition-colors"
                    >
                        <Trash2 className="w-4 h-4" />
                    </button>
                </div>
            </td>
        </tr>
    )
}

export default function LabProjectsPage() {
    const [projects, setProjects] = useState<LabProject[]>([])
    const [loading, setLoading] = useState(true)
    const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid')
    const [isOrderChanged, setIsOrderChanged] = useState(false)
    const [savingOrder, setSavingOrder] = useState(false)

    const sensors = useSensors(
        useSensor(PointerSensor),
        useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates })
    );

    useEffect(() => {
        fetchProjects()
    }, [])

    const fetchProjects = async () => {
        try {
            // Fetch only 'lab' type projects
            const res = await fetch('/api/projects?type=lab')
            const data = await res.json()
            if (Array.isArray(data)) {
                setProjects(data)
            }
        } catch (error) {
            console.error('Fetch error:', error)
        } finally {
            setLoading(false)
        }
    }

    const handleDragEnd = (event: DragEndEvent) => {
        const { active, over } = event;
        if (over && active.id !== over.id) {
            setProjects((items) => {
                const oldIndex = items.findIndex((item) => item.id === active.id);
                const newIndex = items.findIndex((item) => item.id === over.id);
                return arrayMove(items, oldIndex, newIndex);
            });
            setIsOrderChanged(true)
        }
    };

    const saveOrder = async () => {
        setSavingOrder(true)
        try {
            const orderData = projects.map((p, index) => ({ id: p.id, order: index }))
            const res = await fetch('/api/projects/reorder', { // Re-use existing reorder endpoint
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ projects: orderData })
            })
            if (res.ok) {
                setIsOrderChanged(false)
                alert("Sıralama başarıyla güncellendi!")
            } else throw new Error("Failed")
        } catch (e) {
            alert("Hata oluştu")
        } finally {
            setSavingOrder(false)
        }
    }

    const handleDelete = async (id: number) => {
        if (!confirm('Silmek istediğinize emin misiniz?')) return
        try {
            const res = await fetch(`/api/projects?id=${id}`, { method: 'DELETE' })
            if (res.ok) setProjects(prev => prev.filter(p => p.id !== id))
        } catch (e) { alert('Hata') }
    }

    if (loading) return <div className="p-20 text-center animate-pulse">Laboratuvar verileri yükleniyor...</div>

    return (
        <div className="p-8 max-w-7xl mx-auto space-y-8">
            {/* Header */}
            <div className="flex flex-col lg:flex-row items-center justify-between gap-6">
                <div>
                    <h1 className="text-3xl font-bold flex items-center gap-3">
                        <span className="text-4xl bg-gradient-to-r from-purple-500 to-indigo-600 bg-clip-text text-transparent">Vogo Labs</span>
                    </h1>
                    <p className="text-muted-foreground mt-2">Deneysel ve iç projelerimizin yönetim merkezi.</p>
                </div>
                <div className="flex gap-3">
                    {isOrderChanged && (
                        <button
                            onClick={saveOrder}
                            disabled={savingOrder}
                            className="px-6 py-3 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl font-bold transition-all shadow-lg shadow-indigo-500/20"
                        >
                            <Save className="w-5 h-5 inline mr-2" />
                            {savingOrder ? '...' : 'Sıralamayı Kaydet'}
                        </button>
                    )}
                    <Link
                        href="/admin/laboratuvar/new"
                        className="px-6 py-3 bg-emerald-600 hover:bg-emerald-500 text-white rounded-xl font-bold transition-all shadow-lg flex items-center gap-2"
                    >
                        <Plus className="w-5 h-5" />
                        Yeni Proje Ekle
                    </Link>
                </div>
            </div>

            {/* Toolbar */}
            <div className="flex justify-end mb-4">
                <div className="flex bg-card border border-border rounded-lg p-1">
                    <button onClick={() => setViewMode('grid')} className={cn("p-2 rounded", viewMode === 'grid' && "bg-muted shadow")}><LayoutGrid className="w-4 h-4" /></button>
                    <button onClick={() => setViewMode('list')} className={cn("p-2 rounded", viewMode === 'list' && "bg-muted shadow")}><ListIcon className="w-4 h-4" /></button>
                </div>
            </div>

            {/* List */}
            <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
                <SortableContext items={projects.map(p => p.id)} strategy={verticalListSortingStrategy}>
                    {viewMode === 'grid' ? (
                        <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-6">
                            {projects.map(project => (
                                <SortableLabProject key={project.id} project={project} viewMode="grid" handleDelete={handleDelete} />
                            ))}
                        </div>
                    ) : (
                        <div className="bg-card border border-border rounded-3xl overflow-hidden">
                            <table className="w-full text-left">
                                <tbody className="divide-y divide-border">
                                    {projects.map(project => (
                                        <SortableLabProject key={project.id} project={project} viewMode="list" handleDelete={handleDelete} />
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    )}
                </SortableContext>
            </DndContext>

            {projects.length === 0 && (
                <div className="text-center py-20 opacity-50">
                    <Briefcase className="w-16 h-16 mx-auto mb-4" />
                    <p>Henüz laboratuvar projesi eklenmemiş.</p>
                </div>
            )}
        </div>
    )
}

"use client"

import { useState, useEffect } from "react"
import { Mail, Search, Star, Trash2, Reply, MoreHorizontal, User, Clock, Loader2 } from "lucide-react"

export default function MessagesAdminPage() {
    const [messages, setMessages] = useState<any[]>([])
    const [selectedId, setSelectedId] = useState<number | null>(null)
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        loadMessages()
    }, [])

    const loadMessages = () => {
        setLoading(true)
        fetch('/api/messages')
            .then(res => res.json())
            .then(data => {
                setMessages(data)
                setLoading(false)
                if (data.length > 0 && !selectedId) setSelectedId(data[0].id)
            })
            .catch(err => {
                console.error(err)
                setLoading(false)
            })
    }

    const handleDelete = async (id: number) => {
        if (!confirm('Bu mesajı silmek istediğinizden emin misiniz?')) return

        try {
            const res = await fetch('/api/messages', {
                method: 'DELETE',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ id })
            })

            if (res.ok) {
                setSelectedId(null)
                loadMessages()
            }
        } catch (error) {
            console.error('Delete error:', error)
        }
    }

    const markAsRead = async (id: number, is_read: boolean) => {
        try {
            await fetch('/api/messages', {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ id, is_read })
            })
            loadMessages()
        } catch (error) {
            console.error('Mark as read error:', error)
        }
    }

    const selectedMessage = messages.find(m => m.id === selectedId)

    if (loading) {
        return (
            <div className="flex h-[calc(100vh-64px)] items-center justify-center">
                <Loader2 className="w-8 h-8 text-emerald-500 animate-spin" />
            </div>
        )
    }

    return (
        <div className="flex h-[calc(100vh-64px)] overflow-hidden">

            {/* List */}
            <div className="w-full md:w-1/3 border-r border-border bg-card/50 flex flex-col">
                <div className="p-4 border-b border-border">
                    <h1 className="text-xl font-bold text-foreground mb-4 flex items-center gap-2">
                        <Mail className="w-5 h-5 text-emerald-500" /> Gelen Kutusu
                    </h1>
                    <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                        <input
                            type="text"
                            placeholder="Mesajlarda ara..."
                            className="w-full bg-background border border-border rounded-xl pl-10 pr-4 py-2 text-sm text-foreground focus:outline-none focus:border-emerald-500"
                        />
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto">
                    {messages.length === 0 ? (
                        <div className="p-8 text-center text-slate-500 text-sm">Hiç mesaj yok.</div>
                    ) : (
                        messages.map((msg) => (
                            <div
                                key={msg.id}
                                onClick={() => setSelectedId(msg.id)}
                                className={`p-4 border-b border-border cursor-pointer hover:bg-muted/50 transition-colors ${selectedId === msg.id ? 'bg-emerald-500/5 border-l-2 border-l-emerald-500' : 'border-l-2 border-l-transparent'}`}
                            >
                                <div className="flex justify-between items-start mb-1">
                                    <h4 className={`text-sm font-bold ${!msg.is_read ? 'text-foreground' : 'text-muted-foreground'}`}>{msg.name}</h4>
                                    <span className="text-xs text-slate-500">
                                        {new Date(msg.created_at || Date.now()).toLocaleDateString('tr-TR', { day: 'numeric', month: 'short' })}
                                    </span>
                                </div>
                                <p className={`text-sm mb-1 ${!msg.is_read ? 'text-foreground' : 'text-muted-foreground'}`}>{msg.subject || 'Konu Yok'}</p>
                                <p className="text-xs text-slate-500 line-clamp-1">{msg.message}</p>
                            </div>
                        ))
                    )}
                </div>
            </div>

            {/* Detail */}
            <div className="hidden md:flex flex-1 flex-col bg-background">
                {selectedMessage ? (
                    <>
                        <div className="h-16 border-b border-border flex items-center justify-between px-8 bg-card/50">
                            <div className="flex gap-2">
                                <button className="p-2 hover:bg-muted rounded-lg text-muted-foreground hover:text-foreground" title="Yanıtla">
                                    <Reply className="w-5 h-5" />
                                </button>
                                <button
                                    onClick={() => handleDelete(selectedMessage.id)}
                                    className="p-2 hover:bg-muted rounded-lg text-muted-foreground hover:text-red-400"
                                    title="Sil"
                                >
                                    <Trash2 className="w-5 h-5" />
                                </button>
                            </div>
                            <div className="flex gap-2">
                                <button className="p-2 hover:bg-muted rounded-lg text-muted-foreground hover:text-yellow-400"><Star className="w-5 h-5" /></button>
                                <button className="p-2 hover:bg-muted rounded-lg text-muted-foreground hover:text-foreground"><MoreHorizontal className="w-5 h-5" /></button>
                            </div>
                        </div>

                        <div className="flex-1 p-8 overflow-y-auto">
                            <h2 className="text-2xl font-bold text-foreground mb-6">{selectedMessage.subject || 'Başlıksız Mesaj'}</h2>

                            <div className="flex items-center gap-4 mb-8">
                                <div className="w-12 h-12 rounded-full bg-muted flex items-center justify-center text-muted-foreground">
                                    <User className="w-6 h-6" />
                                </div>
                                <div>
                                    <p className="text-foreground font-bold">{selectedMessage.name} <span className="text-slate-500 font-normal text-sm">&lt;{selectedMessage.email}&gt;</span></p>
                                    <p className="text-slate-500 text-xs flex items-center gap-1 mt-0.5">
                                        <Clock className="w-3 h-3" /> {new Date(selectedMessage.created_at || Date.now()).toLocaleString('tr-TR')}
                                    </p>
                                </div>
                            </div>

                            <div className="prose prose-invert prose-emerald max-w-none text-muted-foreground leading-relaxed font-light whitespace-pre-wrap">
                                {selectedMessage.message}
                            </div>
                        </div>

                        <div className="p-4 border-t border-border bg-card/30">
                            <a href={`mailto:${selectedMessage.email}?subject=Ynt: ${selectedMessage.subject}`} className="inline-flex px-6 py-3 bg-emerald-500 text-white rounded-xl font-bold hover:bg-emerald-600 transition-colors items-center gap-2">
                                <Reply className="w-4 h-4" /> E-posta ile Yanıtla
                            </a>
                        </div>
                    </>
                ) : (
                    <div className="flex-1 flex items-center justify-center text-slate-500">
                        <div className="text-center">
                            <Mail className="w-12 h-12 mx-auto mb-4 opacity-20" />
                            <p>Görüntülenecek mesaj yok.</p>
                        </div>
                    </div>
                )}
            </div>
        </div>
    )
}

"use client"

import { useState, useEffect } from "react"
import { useParams, useRouter } from "next/navigation"
import { Save, ArrowLeft, Layout, Type, Image as ImageIcon, Link as LinkIcon, Loader2, FileText } from "lucide-react"
import Link from "next/link"

export default function PageEditor() {
    const params = useParams()
    const router = useRouter()
    const slug = params?.slug as string

    const [content, setContent] = useState<any>(null)
    const [loading, setLoading] = useState(true)
    const [saving, setSaving] = useState(false)

    useEffect(() => {
        if (!slug) return

        // Fetch current content
        fetch(`/api/pages?slug=${slug}`)
            .then(res => res.json())
            .then(data => {
                setContent(data)
                setLoading(false)
            })
            .catch(err => {
                console.error(err)
                setLoading(false)
            })
    }, [slug])

    const handleSave = async () => {
        setSaving(true)
        try {
            const res = await fetch('/api/pages', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ slug, content })
            })

            if (res.ok) alert('Sayfa içeriği güncellendi!')
            else throw new Error('Update failed')

        } catch (error) {
            alert('Kaydetme başarısız.')
        } finally {
            setSaving(false)
        }
    }

    const updateField = (section: string, field: string, value: string) => {
        setContent((prev: any) => ({
            ...prev,
            [section]: {
                ...prev[section],
                [field]: value
            }
        }))
    }

    if (loading) return <div className="p-8 flex justify-center"><Loader2 className="animate-spin text-emerald-500 w-8 h-8" /></div>

    // Sayfa Tiplerine Göre Form Renderlama
    const renderForm = () => {
        if (!content) return <div>İçerik bulunamadı.</div>

        // --- HOME PAGE EDIT FORM ---
        if (slug === 'home') {
            return (
                <div className="space-y-8">
                    {/* Hero Section */}
                    <div className="bg-card border border-border rounded-xl p-6">
                        <h2 className="text-xl font-bold mb-4 flex items-center gap-2 border-b border-border pb-2">
                            <Layout className="w-5 h-5 text-emerald-500" /> Hero Alanı (Giriş)
                        </h2>

                        <div className="grid gap-6">
                            <div>
                                <label className="block text-sm font-medium text-muted-foreground mb-2 flex items-center gap-2">
                                    <Type className="w-4 h-4" /> Ana Başlık
                                </label>
                                <textarea
                                    value={content.hero?.title || ''}
                                    onChange={(e) => updateField('hero', 'title', e.target.value)}
                                    rows={2}
                                    className="w-full bg-background border border-border rounded-lg p-3 focus:border-emerald-500 outline-none"
                                />
                                <p className="text-xs text-muted-foreground mt-1">Satır kırmak için Enter kullanın.</p>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-muted-foreground mb-2 flex items-center gap-2">
                                    <Type className="w-4 h-4" /> Alt Başlık / Açıklama
                                </label>
                                <textarea
                                    value={content.hero?.subtitle || ''}
                                    onChange={(e) => updateField('hero', 'subtitle', e.target.value)}
                                    rows={3}
                                    className="w-full bg-background border border-border rounded-lg p-3 focus:border-emerald-500 outline-none"
                                />
                            </div>

                            <div className="grid md:grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-muted-foreground mb-2 flex items-center gap-2">
                                        <LinkIcon className="w-4 h-4" /> Buton Metni
                                    </label>
                                    <input
                                        type="text"
                                        value={content.hero?.buttonText || ''}
                                        onChange={(e) => updateField('hero', 'buttonText', e.target.value)}
                                        className="w-full bg-background border border-border rounded-lg p-3 focus:border-emerald-500 outline-none"
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-muted-foreground mb-2 flex items-center gap-2">
                                        <LinkIcon className="w-4 h-4" /> Buton Linki
                                    </label>
                                    <input
                                        type="text"
                                        value={content.hero?.buttonLink || ''}
                                        onChange={(e) => updateField('hero', 'buttonLink', e.target.value)}
                                        className="w-full bg-background border border-border rounded-lg p-3 focus:border-emerald-500 outline-none"
                                    />
                                </div>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-muted-foreground mb-2 flex items-center gap-2">
                                    <ImageIcon className="w-4 h-4" /> Kapak Görseli URL
                                </label>
                                <div className="flex gap-2">
                                    <input
                                        type="text"
                                        value={content.hero?.imageUrl || ''}
                                        onChange={(e) => updateField('hero', 'imageUrl', e.target.value)}
                                        placeholder="https://..."
                                        className="w-full bg-background border border-border rounded-lg p-3 focus:border-emerald-500 outline-none"
                                    />
                                </div>
                                {content.hero?.imageUrl && (
                                    <div className="mt-2 w-full h-40 rounded-lg overflow-hidden border border-border bg-slate-900/50">
                                        <img src={content.hero.imageUrl} alt="Önizleme" className="w-full h-full object-cover opacity-70" />
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>

                    {/* Stats Section */}
                    <div className="bg-card border border-border rounded-xl p-6">
                        <h2 className="text-xl font-bold mb-4 flex items-center gap-2 border-b border-border pb-2">
                            <Layout className="w-5 h-5 text-emerald-500" /> İstatistikler
                        </h2>
                        <div className="grid md:grid-cols-3 gap-4">
                            <div>
                                <label className="block text-sm font-medium text-muted-foreground mb-2">Mutlu Müşteri</label>
                                <input
                                    type="text"
                                    value={content.stats?.happyClients || ''}
                                    onChange={(e) => updateField('stats', 'happyClients', e.target.value)}
                                    className="w-full bg-background border border-border rounded-lg p-3"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-muted-foreground mb-2">Proje Sayısı</label>
                                <input
                                    type="text"
                                    value={content.stats?.projects || ''}
                                    onChange={(e) => updateField('stats', 'projects', e.target.value)}
                                    className="w-full bg-background border border-border rounded-lg p-3"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-muted-foreground mb-2">Deneyim Yılı</label>
                                <input
                                    type="text"
                                    value={content.stats?.years || ''}
                                    onChange={(e) => updateField('stats', 'years', e.target.value)}
                                    className="w-full bg-background border border-border rounded-lg p-3"
                                />
                            </div>
                        </div>
                    </div>
                </div>
            )
        }

        // --- SERVICES PAGE EDIT FORM ---
        if (slug === 'services') {
            const servicesList = content.servicesList || []

            const handleAddService = () => {
                const newService = { title: "Yeni Hizmet", description: "Hizmet açıklaması...", icon: "Code" }
                setContent((prev: any) => ({ ...prev, servicesList: [...servicesList, newService] }))
            }

            const handleRemoveService = (index: number) => {
                if (!confirm('Bu hizmeti silmek istediğinize emin misiniz?')) return
                const newList = [...servicesList]
                newList.splice(index, 1)
                setContent((prev: any) => ({ ...prev, servicesList: newList }))
            }

            const updateService = (index: number, field: string, value: string) => {
                const newList = [...servicesList]
                newList[index] = { ...newList[index], [field]: value }
                setContent((prev: any) => ({ ...prev, servicesList: newList }))
            }

            return (
                <div className="space-y-8">
                    {/* Hero Section */}
                    <div className="bg-card border border-border rounded-xl p-6">
                        <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
                            <Layout className="w-5 h-5 text-emerald-500" /> Hizmetler Başlık Alanı
                        </h2>
                        <div className="grid gap-4">
                            <div>
                                <label className="block text-sm font-medium text-muted-foreground mb-2">Sayfa Başlığı</label>
                                <input
                                    type="text"
                                    value={content.hero?.title || ''}
                                    onChange={(e) => updateField('hero', 'title', e.target.value)}
                                    className="w-full bg-background border border-border rounded-lg p-3"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-muted-foreground mb-2">Açıklama Metni</label>
                                <textarea
                                    value={content.hero?.subtitle || ''}
                                    onChange={(e) => updateField('hero', 'subtitle', e.target.value)}
                                    rows={3}
                                    className="w-full bg-background border border-border rounded-lg p-3"
                                />
                            </div>
                        </div>
                    </div>

                    {/* Services List Management */}
                    <div className="space-y-4">
                        <div className="flex items-center justify-between">
                            <h2 className="text-xl font-bold flex items-center gap-2">
                                <Layout className="w-5 h-5 text-emerald-500" /> Hizmet Kartları
                            </h2>
                            <button
                                onClick={handleAddService}
                                className="px-4 py-2 bg-emerald-500/10 text-emerald-500 hover:bg-emerald-500 hover:text-white rounded-lg font-bold text-sm transition-colors"
                            >
                                + Yeni Hizmet Ekle
                            </button>
                        </div>

                        <div className="grid gap-4">
                            {servicesList.map((service: any, index: number) => (
                                <div key={index} className="bg-card border border-border rounded-xl p-6 relative group">
                                    <button
                                        onClick={() => handleRemoveService(index)}
                                        className="absolute top-4 right-4 text-slate-500 hover:text-red-500 p-2 opacity-0 group-hover:opacity-100 transition-opacity"
