                                    Henüz eklenmiş hizmet yok.
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            )
        }

        // --- ABOUT PAGE EDIT FORM ---
        if (slug === 'about') {
            return (
                <div className="space-y-8">
                    {/* Hero Section */}
                    <div className="bg-card border border-border rounded-xl p-6">
                        <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
                            <Layout className="w-5 h-5 text-emerald-500" /> Hakkımızda Başlık
                        </h2>
                        <div className="grid gap-4">
                            <div>
                                <label className="block text-sm font-medium text-muted-foreground mb-2">Başlık</label>
                                <input
                                    type="text"
                                    value={content.hero?.title || ''}
                                    onChange={(e) => updateField('hero', 'title', e.target.value)}
                                    className="w-full bg-background border border-border rounded-lg p-3"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-muted-foreground mb-2">Alt Metin</label>
                                <textarea
                                    value={content.hero?.subtitle || ''}
                                    onChange={(e) => updateField('hero', 'subtitle', e.target.value)}
                                    rows={3}
                                    className="w-full bg-background border border-border rounded-lg p-3"
                                />
                            </div>
                        </div>
                    </div>

                    {/* Detailed Content */}
                    <div className="bg-card border border-border rounded-xl p-6">
                        <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
                            <FileText className="w-5 h-5 text-emerald-500" /> Detaylı İçerik
                        </h2>
                        <div className="grid gap-6">
                            <div>
                                <label className="block text-sm font-medium text-muted-foreground mb-2">Biz Kimiz? (Ana Metin)</label>
                                <textarea
                                    value={content.mainContent || ''}
                                    onChange={(e) => setContent((prev: any) => ({ ...prev, mainContent: e.target.value }))}
                                    rows={6}
                                    className="w-full bg-background border border-border rounded-lg p-3"
                                />
                            </div>
                            <div className="grid md:grid-cols-2 gap-6">
                                <div>
                                    <label className="block text-sm font-medium text-muted-foreground mb-2">Misyonumuz</label>
                                    <textarea
                                        value={content.mission || ''}
                                        onChange={(e) => setContent((prev: any) => ({ ...prev, mission: e.target.value }))}
                                        rows={4}
                                        className="w-full bg-background border border-border rounded-lg p-3"
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-muted-foreground mb-2">Vizyonumuz</label>
                                    <textarea
                                        value={content.vision || ''}
                                        onChange={(e) => setContent((prev: any) => ({ ...prev, vision: e.target.value }))}
                                        rows={4}
                                        className="w-full bg-background border border-border rounded-lg p-3"
                                    />
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            )
        }

        // --- GENERIC / OTHER PAGES ---
        return (
            <div className="bg-card border border-border rounded-xl p-6">
                <h2 className="text-xl font-bold mb-4">Genel İçerik Düzenleyici</h2>
                <div className="space-y-4">
                    {/* Generic Hero Fields if exist */}
                    <div>
                        <label className="block text-sm font-medium text-muted-foreground mb-2">Başlık</label>
                        <input
                            type="text"
                            value={content.hero?.title || ''}
                            onChange={(e) => updateField('hero', 'title', e.target.value)}
                            className="w-full bg-background border border-border rounded-lg p-3"
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-muted-foreground mb-2">Alt Başlık</label>
                        <textarea
                            value={content.hero?.subtitle || ''}
                            onChange={(e) => updateField('hero', 'subtitle', e.target.value)}
                            rows={3}
                            className="w-full bg-background border border-border rounded-lg p-3"
                        />
                    </div>
                </div>
            </div>
        )
    }

    return (
        <div className="p-8 max-w-5xl mx-auto">
            <div className="flex items-center justify-between mb-8">
                <div className="flex items-center gap-4">
                    <Link href="/admin/pages" className="p-2 hover:bg-muted rounded-full transition-colors">
                        <ArrowLeft className="w-5 h-5" />
                    </Link>
                    <div>
                        <h1 className="text-3xl font-bold text-foreground capitalize">
                            {slug === 'home' ? 'Anasayfa' : slug} Düzenle
                        </h1>
                        <p className="text-muted-foreground text-sm">Sayfa içeriğini buradan yönetebilirsiniz.</p>
                    </div>
                </div>

                <button
                    onClick={handleSave}
                    disabled={saving}
                    className="px-6 py-3 bg-emerald-500 hover:bg-emerald-600 text-white rounded-xl font-bold flex items-center gap-2 shadow-lg shadow-emerald-500/20 active:scale-95 transition-all disabled:opacity-70"
                >
                    {saving ? <Loader2 className="animate-spin w-5 h-5" /> : <Save className="w-5 h-5" />}
                    {saving ? 'Kaydediliyor...' : 'Kaydet'}
                </button>
            </div>

            {renderForm()}
        </div>
    )
}

"use client"

import { useState, useEffect } from "react"
import { ArrowLeft, Save, Trash2, Briefcase, Image as ImageIcon } from "lucide-react"
import Link from "next/link"
import { useRouter, useParams } from "next/navigation"
import ImageUploader from "@/components/admin/ImageUploader"

export default function EditProjectPage() {
    const router = useRouter()
    const params = useParams()
    const { id } = params

    const [loading, setLoading] = useState(true)
    const [saving, setSaving] = useState(false)
    const [deleting, setDeleting] = useState(false)
    const [formData, setFormData] = useState<any>({
        title: "",
        client: "",
        category: "Web Tasarım",
        image: "",
        desc: ""
    })

    // Veriyi Getir
    useEffect(() => {
        const fetchData = async () => {
            try {
                const res = await fetch('/api/projects')
                const data = await res.json()
                const project = data.find((item: any) => item.id == id)
                if (project) {
                    setFormData(project)
                } else {
                    alert("Proje bulunamadı!")
                    router.push('/admin/portfolio')
                }
            } catch (error) {
                console.error("Veri çekme hatası:", error)
            } finally {
                setLoading(false)
            }
        }
        fetchData()
    }, [id, router])

    // Güncelle (PUT)
    const handleUpdate = async (e: React.FormEvent) => {
        e.preventDefault()
        setSaving(true)
        try {
            const res = await fetch('/api/projects', {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(formData),
            })

            if (!res.ok) throw new Error('Güncellenemedi')

            alert("Proje güncellendi!")
            router.push('/admin/portfolio')
            router.refresh()
        } catch (error) {
            console.error(error)
            alert("Bir hata oluştu!")
        } finally {
            setSaving(false)
        }
    }

    // Sil (DELETE)
    const handleDelete = async () => {
        if (!confirm("Bu projeyi silmek istediğinize emin misiniz?")) return

        setDeleting(true)
        try {
            const res = await fetch(`/api/projects?id=${id}`, {
                method: 'DELETE',
            })

            if (!res.ok) throw new Error('Silinemedi')

            alert("Proje silindi.")
            router.push('/admin/portfolio')
            router.refresh()
        } catch (error) {
            console.error(error)
            alert("Silme işlemi başarısız!")
        } finally {
            setDeleting(false)
        }
    }

    if (loading) return <div className="p-8 text-white">Yükleniyor...</div>

    return (
        <div className="p-8 max-w-5xl mx-auto space-y-8">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 sticky top-16 z-20 bg-slate-950/80 backdrop-blur-md py-4 -my-4 border-b border-white/5">
                <div className="flex items-center gap-4">
                    <Link href="/admin/portfolio" className="p-2 hover:bg-slate-900 rounded-lg text-slate-400 hover:text-white transition-colors">
                        <ArrowLeft className="w-5 h-5" />
                    </Link>
                    <div>
                        <h1 className="text-2xl font-bold text-white">Projeyi Düzenle</h1>
                        <p className="text-slate-400 text-sm">#{id} numaralı proje üzerinde çalışıyorsunuz.</p>
                    </div>
                </div>
                <div className="flex gap-3">
                    <button
                        onClick={handleDelete}
                        disabled={deleting}
                        className="px-4 py-2 bg-red-500/10 hover:bg-red-500/20 text-red-500 rounded-xl font-bold transition-all border border-red-500/20 flex items-center gap-2"
                    >
                        <Trash2 className="w-4 h-4" /> {deleting ? 'Siliniyor...' : 'Sil'}
                    </button>
                    <button
                        onClick={handleUpdate}
                        disabled={saving}
                        className="px-6 py-2 bg-emerald-500 hover:bg-emerald-600 disabled:opacity-50 disabled:cursor-not-allowed text-white rounded-xl font-bold transition-all shadow-lg shadow-emerald-500/20 flex items-center gap-2 active:scale-95"
                    >
                        <Save className="w-4 h-4" /> {saving ? 'Kaydediliyor...' : 'Kaydet'}
                    </button>
                </div>
            </div>

            <div className="grid lg:grid-cols-2 gap-8">
                {/* Sol: Genel Bilgiler */}
                <div className="space-y-6">
                    <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 space-y-4">
                        <div>
                            <label className="block text-slate-400 text-sm font-medium mb-2">Proje Başlığı</label>
                            <input
                                type="text"
                                className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-emerald-500"
                                value={formData.title}
                                onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                            />
                        </div>
                        <div>
                            <label className="block text-slate-400 text-sm font-medium mb-2">Müşteri Adı</label>
                            <input
                                type="text"
                                className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-emerald-500"
                                value={formData.client}
                                onChange={(e) => setFormData({ ...formData, client: e.target.value })}
                            />
                        </div>
                        <div>
                            <label className="block text-slate-400 text-sm font-medium mb-2">Kategori</label>
                            <select
                                className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-emerald-500"
                                value={formData.category}
                                onChange={(e) => setFormData({ ...formData, category: e.target.value })}
                            >
                                {["Web Tasarım", "Reklam Yönetimi", "E-Ticaret", "AI Çözümleri", "Marka", "Yazılım"].map(cat => (
                                    <option key={cat} value={cat}>{cat}</option>
                                ))}
                            </select>
                        </div>
                    </div>

                    <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 space-y-4">
                        <label className="block text-slate-400 text-sm font-medium mb-2">Açıklama (Kısa)</label>
                        <textarea
                            className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-emerald-500 h-32 resize-none"
                            value={formData.desc || formData.description}
                            onChange={(e) => setFormData({ ...formData, desc: e.target.value })}
                        />
                    </div>
                </div>

                {/* Sağ: Görsel */}
                <div className="space-y-6">
                    <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 space-y-4">
                        <h3 className="font-bold text-white flex items-center gap-2 text-sm border-b border-slate-800 pb-3">
                            <ImageIcon className="w-4 h-4 text-emerald-500" />
                            Proje Görseli
                        </h3>
                        <ImageUploader
                            value={formData.image}
                            onChange={(url) => setFormData({ ...formData, image: url })}
                        />
                    </div>
                </div>
            </div>
        </div>
    )
}

"use client"
import { useEffect, useState } from "react"
import { useParams, useRouter } from "next/navigation"
import { Briefcase, ArrowLeft, Calendar, DollarSign, Building2, CheckCircle2, Printer, StickyNote, Plus, Trash2, Edit2, Loader2 } from "lucide-react"
import Link from "next/link"
import TaskDetailModal from "@/components/admin/tasks/TaskDetailModal"

interface Note {
    id: number
    content: string
    created_at: string
}

/* eslint-disable @typescript-eslint/no-explicit-any */
export default function ProjectDetailPage() {
    const params = useParams()
    const router = useRouter()
    const [project, setProject] = useState<any>(null)
    const [loading, setLoading] = useState(true)

    // Notes State (local storage for now, can be moved to API)
    const [notes, setNotes] = useState<Note[]>([])
    const [newNote, setNewNote] = useState("")
    const [addingNote, setAddingNote] = useState(false)

    // Quick Task State
    const [newTaskTitle, setNewTaskTitle] = useState("")
    const [addingTask, setAddingTask] = useState(false)
    const [selectedTask, setSelectedTask] = useState<any>(null)

    useEffect(() => {
        if (params.id) {
            fetchProject(params.id as string)
            fetchNotes(params.id as string)
            // Her render'da güncel task'ları yükle
            refreshProjectTasks(params.id as string)
        }
    }, [params.id])

    const fetchProject = async (id: string) => {
        try {
            const res = await fetch(`/api/projects?id=${id}`)
            if (res.ok) {
                const data = await res.json()
                if (data && data.id) {
                    setProject(data)
                    return
                }
            }

            // API'den gelmediyse ve Dev ortamındaysak, HATA ATMADAN ÖNCE Mock'a bak
            if (process.env.NODE_ENV === 'development') {
                console.log("⚠️ Dev Mode: Looking for Mock Project")
                const mockP = require('@/lib/mock-data').MOCK_PROJECTS.find((p: any) => p.id == id)
                if (mockP) {
                    // 1. Önce LocalStorage'dan güncel görevleri çek
                    let allTasks = require('@/lib/mock-data').MOCK_TASKS
                    try {
                        if (typeof window !== 'undefined') {
                            const local = localStorage.getItem('mock_tasks')
                            if (local) allTasks = JSON.parse(local)
                        }
                    } catch (e) { console.error("LS Read Error", e) }

                    // 2. Bu projeye ait olanları filtrele
                    const mockTasks = allTasks.filter((t: any) => t.project_id == id)

                    // 3. Proje verisine ekle
                    setProject({ ...mockP, tasks: mockTasks })
                    return
                }
            }

            throw new Error('Proje bulunamadı')

        } catch (error) {
            console.error(error)
            alert("Proje bulunamadı")
            router.push('/admin/projects')
        } finally {
            setLoading(false)
        }
    }

    const refreshProjectTasks = (projectId: string) => {
        if (process.env.NODE_ENV === 'development') {
            // localStorage'dan güncel task listesini al
            try {
                const stored = localStorage.getItem('mock_tasks')
                if (stored) {
                    const allTasks = JSON.parse(stored)
                    const projectTasks = allTasks.filter((t: any) => t.project_id == projectId)
                    setProject((prev: any) => prev ? { ...prev, tasks: projectTasks } : null)
                }
            } catch (e) {
                console.error("Task refresh error:", e)
            }
        } else {
            // Production: API'den task'ları çek
            fetch(`/api/tasks`)
                .then(r => r.json())
                .then(allTasks => {
                    const projectTasks = allTasks.filter((t: any) => t.project_id == projectId)
                    setProject((prev: any) => prev ? { ...prev, tasks: projectTasks } : null)
                })
                .catch(e => console.error("Task fetch error:", e))
        }
    }

    const fetchNotes = (id: string) => {
        // Using localStorage for notes (can be migrated to API later)
        try {
            const storedNotes = localStorage.getItem(`project_notes_${id}`)
            if (storedNotes) {
                setNotes(JSON.parse(storedNotes))
            }
        } catch (e) {
            console.error('Failed to fetch notes:', e)
        }
    }

    const handleQuickAddTask = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!newTaskTitle.trim()) return

        setAddingTask(true)

        const tempId = Date.now()
        const newTask = {
            id: tempId,
            title: newTaskTitle,
            status: 'todo',
            project_id: project.id,
            projects: {
                id: project.id,
                name: project.name || project.title || "Proje",
                title: project.name || project.title || "Proje"
            },
            priority: 'medium',
            assigned_to: null,
            created_at: new Date().toISOString()
        }

        // Optimistic UI Update
        const updatedTasks = [newTask, ...(project.tasks || [])]
        setProject({ ...project, tasks: updatedTasks })
        setNewTaskTitle("")

        // Dev Mode: Sync with LocalStorage for Tasks Page Visibility
        if (process.env.NODE_ENV === 'development') {
            console.log("Mock Task Added & Synced:", newTask)

            try {
                // 1. Get existing mock tasks
                let localTasks = []
                const stored = localStorage.getItem('mock_tasks')
                if (stored) {
                    localTasks = JSON.parse(stored)
                } else {
                    localTasks = require('@/lib/mock-data').MOCK_TASKS
                }

                // 2. Add new task
                localTasks.unshift(newTask)

                // 3. Save back
                localStorage.setItem('mock_tasks', JSON.stringify(localTasks))

                // 4. Task board'a bildir
                if (typeof window !== 'undefined') {
                    window.dispatchEvent(new Event('tasks-updated'))
                }

            } catch (e) { console.error("LS Sync Error", e) }

            setTimeout(() => setAddingTask(false), 500)
            return
        }

        try {
            await fetch('/api/tasks', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ ...newTask, id: undefined })
            })
        } catch (error) {
            console.error(error)
            alert("Görev eklenirken hata oluştu")
        } finally {
            setAddingTask(false)
        }
    }

    const toggleTaskStatus = async (task: any, e?: React.MouseEvent) => {
        if (e) e.stopPropagation() // Prevent modal opening

        const newStatus = task.status === 'done' ? 'todo' : 'done'

        // Optimistic UI Update
        const updatedTasks = project.tasks.map((t: any) =>
            t.id === task.id ? { ...t, status: newStatus } : t
        )
        setProject({ ...project, tasks: updatedTasks })

        // Dev Mode: Sync with LocalStorage
        if (process.env.NODE_ENV === 'development') {
            try {
                let localTasks = []
                const stored = localStorage.getItem('mock_tasks')
                if (stored) localTasks = JSON.parse(stored)
                else localTasks = require('@/lib/mock-data').MOCK_TASKS

                // Update status in global store
                const globalUpdated = localTasks.map((t: any) =>
                    t.id === task.id ? { ...t, status: newStatus } : t
                )
                localStorage.setItem('mock_tasks', JSON.stringify(globalUpdated))
            } catch (e) { console.error("LS Sync Error", e) }
            return
        }

        try {
            await fetch('/api/tasks', {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ id: task.id, status: newStatus })
            })
        } catch (e) {
            console.error(e)
            // Revert changes could be handled here
        }
    }

    const handleAddNote = (e: React.FormEvent) => {
        e.preventDefault()
        if (!newNote.trim()) return

        setAddingNote(true)
        try {
            const newNoteObj: Note = {
                id: Date.now(),
                content: newNote,
                created_at: new Date().toISOString()
            }

            const updatedNotes = [newNoteObj, ...notes]
            setNotes(updatedNotes)
            localStorage.setItem(`project_notes_${params.id}`, JSON.stringify(updatedNotes))
            setNewNote("")
        } catch (error) {
            console.error(error)
            alert('Not eklenirken hata oluştu.')
        } finally {
            setAddingNote(false)
        }
    }

    const handleDeleteNote = (noteId: number) => {
        if (!confirm("Notu silmek istediğinize emin misiniz?")) return

        try {
            const updatedNotes = notes.filter(n => n.id !== noteId)
            setNotes(updatedNotes)
            localStorage.setItem(`project_notes_${params.id}`, JSON.stringify(updatedNotes))
        } catch (error) {
            console.error(error)
            alert('Silme hatası')
        }
    }

    const handlePrint = () => {
        window.print()
    }

    if (loading) return <div className="p-8 text-slate-400">Yükleniyor...</div>
    if (!project) return <div className="p-8 text-slate-400">Proje bulunamadı.</div>

    // Stats Hesaplama
    const totalTasks = project.tasks?.length || 0
    const completedTasks = project.tasks?.filter((t: any) => t.status === 'done').length || 0
    const progress = totalTasks > 0 ? Math.round((completedTasks / totalTasks) * 100) : 0

    return (
        <div className="p-8 max-w-7xl mx-auto space-y-8 print:p-0 print:bg-white print:text-black">
            {/* Header */}
            <div className="flex items-center gap-4 print:hidden">
                <Link href="/admin/projects" className="p-2 bg-muted rounded-lg hover:bg-muted/80 text-muted-foreground hover:text-foreground transition-colors">
                    <ArrowLeft className="w-5 h-5" />
                </Link>
                <div>
                    <div className="flex items-center gap-3">
                        <h1 className="text-3xl font-bold text-foreground">{project.name}</h1>
                        <span className={`px-3 py-1 rounded-full text-xs font-bold border ${project.status === 'completed' ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' :
                            project.status === 'in_progress' ? 'bg-blue-500/10 text-blue-400 border-blue-500/20' :
                                'bg-slate-800 text-slate-400 border-slate-700'
                            }`}>
                            {project.status === 'completed' ? 'Tamamlandı' :
                                project.status === 'in_progress' ? 'Devam Ediyor' : project.status}
                        </span>
                    </div>
                    <p className="text-muted-foreground mt-1 flex items-center gap-2">
                        <Building2 className="w-4 h-4" />
                        {project.clients?.company || project.clients?.name || 'Müşteri Yok'}
                    </p>
                </div>
            </div>

            {/* Print Header (Only visible when printing) */}
            <div className="hidden print:block mb-8">
                <h1 className="text-2xl font-bold">{project.name} - Proje Raporu</h1>
                <p className="text-gray-500">Tarih: {new Date().toLocaleDateString('tr-TR')}</p>
            </div>

            {/* Grid Layout */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 print:block print:space-y-8">

                {/* Sol Kolon: Detaylar */}
                <div className="lg:col-span-2 space-y-8">

                    {/* Açıklama Kartı */}
                    <div className="bg-card border border-border rounded-notebook p-6 print:border-gray-200 print:bg-white print:p-0">
                        <h2 className="text-xl font-bold text-foreground mb-4 flex items-center gap-2 print:text-black">
                            <Briefcase className="w-5 h-5 text-emerald-500 print:text-black" />
                            Proje Detayları
                        </h2>
                        <p className="text-muted-foreground leading-relaxed whitespace-pre-wrap print:text-gray-700">
                            {project.description || 'Açıklama girilmemiş.'}
                        </p>
                    </div>

                    {/* Notlar Bölümü */}
                    <div className="bg-card border border-border rounded-notebook p-6 print:hidden">
                        <h2 className="text-xl font-bold text-foreground mb-4 flex items-center gap-2">
                            <StickyNote className="w-5 h-5 text-yellow-500" />
                            Proje Notları
                        </h2>

                        {/* Not Ekleme Formu */}
                        <form onSubmit={handleAddNote} className="mb-6 flex gap-2">
                            <input
                                type="text"
                                value={newNote}
                                onChange={(e) => setNewNote(e.target.value)}
                                placeholder="Proje ile ilgili not ekle..."
                                className="flex-1 bg-background border border-border rounded-xl px-4 py-2 text-foreground focus:outline-none focus:border-emerald-500"
                            />
                            <button
                                type="submit"
                                disabled={addingNote || !newNote.trim()}
                                className="bg-emerald-600 hover:bg-emerald-500 text-white p-2 rounded-xl disabled:opacity-50 transition-colors"
                            >
                                <Plus className="w-5 h-5" />
                            </button>
                        </form>

                        {/* Not Listesi */}
                        <div className="space-y-3 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
                            {notes.length === 0 ? (
                                <p className="text-slate-500 text-sm text-center py-4">Henüz not eklenmemiş.</p>
                            ) : (
                                notes.map((note) => (
                                    <div key={note.id} className="group flex items-start justify-between bg-muted p-3 rounded-xl border border-border hover:border-border/80 transition-colors">
                                        <div>
                                            <p className="text-foreground text-sm">{note.content}</p>
                                            <span className="text-slate-600 text-[10px] mt-1 block">
                                                {new Date(note.created_at).toLocaleString('tr-TR')}
                                            </span>
                                        </div>
                                        <button
                                            onClick={() => handleDeleteNote(note.id)}
                                            className="opacity-0 group-hover:opacity-100 text-slate-600 hover:text-red-400 transition-all"
                                        >
                                            <Trash2 className="w-3.5 h-3.5" />
                                        </button>
                                    </div>
                                ))
                            )}
                        </div>
                    </div>

                    {/* Görevler Listesi */}
                    <div className="bg-card border border-border rounded-notebook p-6 print:hidden">
                        <div className="flex items-center justify-between mb-4">
                            <h2 className="text-xl font-bold text-foreground flex items-center gap-2">
                                <CheckCircle2 className="w-5 h-5 text-blue-500" />
                                Proje Görevleri
                            </h2>
                            <Link href="/admin/tasks" className="text-sm text-emerald-500 hover:text-emerald-400 font-medium flex items-center gap-1 transition-colors">
                                Tüm Görevleri Yönet
                            </Link>
                        </div>

                        {/* Hızlı Ekleme Formu */}
                        <form onSubmit={handleQuickAddTask} className="mb-6 flex gap-2">
                            <input
                                type="text"
                                value={newTaskTitle}
                                onChange={(e) => setNewTaskTitle(e.target.value)}
                                placeholder="Yeni görev ekle... (Enter)"
                                className="flex-1 bg-background border border-border rounded-xl px-4 py-3 text-foreground focus:outline-none focus:border-emerald-500 transition-all placeholder:text-muted-foreground"
                            />
                            <button
                                type="submit"
                                disabled={addingTask || !newTaskTitle.trim()}
                                className="bg-blue-600 hover:bg-blue-500 text-white p-3 rounded-xl disabled:opacity-50 transition-all active:scale-95 shadow-lg shadow-blue-500/20"
                            >
                                {addingTask ? <Loader2 className="w-5 h-5 animate-spin" /> : <Plus className="w-5 h-5" />}
                            </button>
                        </form>

                        {(!project.tasks || project.tasks.length === 0) ? (
                            <div className="text-center py-8 border border-dashed border-border rounded-2xl">
                                <p className="text-muted-foreground text-sm italic">Henüz görev atanmamış. Yukarıdan ekleyebilirsin.</p>
                            </div>
                        ) : (
                            <div className="space-y-3">
                                {project.tasks.map((task: any) => (
                                    <div
                                        key={task.id}
                                        className={`group flex items-center justify-between p-4 rounded-xl border transition-all cursor-pointer ${task.status === 'done'
                                            ? 'bg-emerald-500/5 border-emerald-500/20 opacity-70'
                                            : 'bg-card hover:bg-muted/50 border-border hover:border-blue-500/30 hover:shadow-md'
                                            }`}
                                        onClick={() => setSelectedTask(task)}
                                    >
                                        <div className="flex items-center gap-4">
                                            <button
                                                onClick={(e) => toggleTaskStatus(task, e)}
                                                className={`w-6 h-6 rounded-full flex items-center justify-center transition-all ${task.status === 'done'
                                                    ? 'bg-emerald-500 text-white scale-110'
                                                    : 'border-2 border-slate-400 text-transparent hover:border-emerald-500'
                                                    }`}>
                                                <CheckCircle2 className="w-4 h-4" />
                                            </button>

                                            <span className={`font-medium transition-all ${task.status === 'done'
                                                ? 'text-muted-foreground line-through decoration-emerald-500/50'
                                                : 'text-foreground'
                                                }`}>
                                                {task.title}
                                            </span>
                                        </div>

                                        <div className="flex items-center gap-3">
                                            {task.priority && (
                                                <span className={`text-[10px] uppercase font-bold px-2 py-0.5 rounded border ${task.priority === 'high' ? 'bg-red-500/10 text-red-500 border-red-500/20' :
                                                    task.priority === 'medium' ? 'bg-yellow-500/10 text-yellow-500 border-yellow-500/20' :
                                                        'bg-white0/10 text-slate-500 border-slate-500/20'
                                                    }`}>
                                                    {task.priority === 'high' ? 'Yüksek' : task.priority === 'medium' ? 'Orta' : 'Düşük'}
                                                </span>
                                            )}
                                            <span className="text-xs text-muted-foreground px-2 py-1 bg-muted rounded hidden sm:inline-block">
                                                {task.assigned_to ? 'Atandı' : 'Atanmadı'}
                                            </span>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>

                </div>

                {/* Sağ Kolon: Özet & Meta */}
                <div className="space-y-6 print:hidden">

                    {/* İlerleme Durumu */}
                    <div className="bg-card border border-border rounded-notebook p-6">
                        <h3 className="text-sm font-bold text-muted-foreground uppercase mb-4">İlerleme</h3>
                        <div className="flex items-end justify-between mb-2">
                            <span className="text-3xl font-bold text-foreground">%{progress}</span>
                            <span className="text-sm text-muted-foreground">{completedTasks}/{totalTasks} Görev</span>
                        </div>
                        <div className="h-2 bg-muted rounded-full overflow-hidden">
                            <div className="h-full bg-emerald-500 transition-all duration-500" style={{ width: `${progress}%` }} />
                        </div>
                    </div>

                    {/* Finansal Özet */}
                    <div className="bg-card border border-border rounded-notebook p-6">
                        <h3 className="text-sm font-bold text-muted-foreground uppercase mb-4">Finansal</h3>
                        <div className="space-y-4">
                            <div>
                                <label className="text-xs text-slate-500 block mb-1">Toplam Bütçe</label>
                                <div className="text-xl font-bold text-foreground flex items-center gap-1">
                                    <DollarSign className="w-5 h-5 text-emerald-500" />
                                    {project.budget ? project.budget.toLocaleString('tr-TR') : '0'} ₺
                                </div>
                            </div>
                            <div className="pt-4 border-t border-border">
                                <label className="text-xs text-muted-foreground block mb-1">Bitiş Tarihi</label>
                                <div className="text-sm font-medium text-foreground flex items-center gap-2">
                                    <Calendar className="w-4 h-4 text-blue-500" />
                                    {project.end_date ? new Date(project.end_date).toLocaleDateString('tr-TR') : 'Belirsiz'}
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Aksiyonlar */}
                    <div className="bg-card border border-border rounded-notebook p-6 space-y-3">
                        <Link
                            href={`/admin/projects/edit/${project.id}`}
                            className="w-full flex items-center justify-center gap-2 py-3 bg-emerald-600 hover:bg-emerald-500 text-white rounded-xl font-bold transition-colors"
                        >
                            <Edit2 className="w-4 h-4" />
                            Projeyi Düzenle
                        </Link>
                        <button
                            onClick={handlePrint}
                            className="w-full flex items-center justify-center gap-2 py-3 bg-muted hover:bg-muted/80 text-foreground rounded-xl font-medium transition-colors"
                        >
                            <Printer className="w-4 h-4" />
                            Rapor Oluştur
                        </button>
                    </div>

                </div>
            </div>

            {/* Task Detail Modal */}
            {selectedTask && (
                <TaskDetailModal
                    task={selectedTask}
                    onClose={() => setSelectedTask(null)}
                    onUpdate={() => {
                        // Refresh project data to reflect changes
                        // For mock/dev, we can just reload from LS or fetchProject
                        if (process.env.NODE_ENV === 'development') {
                            const localTasks = JSON.parse(localStorage.getItem('mock_tasks') || '[]')
                            const updatedProjectTasks = localTasks.filter((t: any) => t.project_id == project.id)
                            setProject((prev: any) => ({ ...prev, tasks: updatedProjectTasks }))
                        } else {
                            fetch(`/api/projects?id=${project.id}`)
                                .then(r => r.json())
                                .then(data => setProject(data))
                        }
                    }}
                    onDelete={() => {
                        // Remove from UI
                        setProject((prev: any) => ({
                            ...prev,
                            tasks: prev.tasks.filter((t: any) => t.id !== selectedTask.id)
                        }))
                        setSelectedTask(null)

                        // Dev Sync
                        if (process.env.NODE_ENV === 'development') {
                            const localTasks = JSON.parse(localStorage.getItem('mock_tasks') || '[]')
                            const filtered = localTasks.filter((t: any) => t.id !== selectedTask.id)
                            localStorage.setItem('mock_tasks', JSON.stringify(filtered))
                        }
                    }}
                    projects={require('@/lib/mock-data').MOCK_PROJECTS} // Pass available projects if needed
                    team={require('@/lib/mock-data').MOCK_TEAM} // Pass available team
                />
            )}
        </div>
    )
}

"use client"

export const dynamic = "force-dynamic"

import { useEffect, useState } from "react"
import { Briefcase, Plus, Calendar, DollarSign, Trash2, Users, Search, Filter, LayoutGrid, List as ListIcon, MoreHorizontal, GripVertical, Save } from "lucide-react"
import Link from "next/link"
import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Card } from "@/components/ui/card"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import {
    DndContext,
    closestCenter,
    KeyboardSensor,
    PointerSensor,
    useSensor,
    useSensors,
    DragEndEvent
} from '@dnd-kit/core';
import {
    arrayMove,
    SortableContext,
    sortableKeyboardCoordinates,
    verticalListSortingStrategy,
    useSortable
} from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';

interface Project {
    id: number
    internalName?: string
    publicTitle?: string
    name?: string // fallback
    description: string
    status: 'completed' | 'in_progress' | 'quote' | 'cancelled'
    budget: number
    end_date: string
    order: number
    client?: {
        name: string
        company: string
    }
}

// Sortable Item Component
function SortableProjectItem({ project, viewMode, statusConfig, formatCurrency, handleDelete }: any) {
    const {
        attributes,
        listeners,
        setNodeRef,
        transform,
        transition,
        isDragging
    } = useSortable({ id: project.id });

    const style = {
        transform: CSS.Transform.toString(transform),
        transition,
        zIndex: isDragging ? 10 : 1,
        opacity: isDragging ? 0.5 : 1,
    };

    if (viewMode === 'grid') {
        return (
            <div
                ref={setNodeRef}
                style={style}
                className="group relative bg-card border border-border rounded-3xl p-6 transition-all hover:border-emerald-500/30 hover:shadow-xl flex flex-col h-full"
            >
                {/* Drag Handle */}
                <div className="absolute top-4 right-4 cursor-grab active:cursor-grabbing p-2 hover:bg-muted rounded-full opacity-0 group-hover:opacity-100 transition-opacity" {...attributes} {...listeners}>
                    <GripVertical className="w-4 h-4 text-slate-400" />
                </div>

                {/* Card Header */}
                <div className="flex items-start justify-between mb-4">
                    <div className="w-12 h-12 bg-muted rounded-notebook flex items-center justify-center text-2xl shadow-inner border border-border">
                        {statusConfig[project.status]?.icon || '📁'}
                    </div>
                </div>

                <div className="flex-1">
                    {/* Internal Name (Admin) */}
                    <div className="text-xs text-emerald-500 font-bold uppercase tracking-wider mb-1">
                        {project.internalName || project.name || 'İsimsiz'}
                    </div>
                    {/* Public Title */}
                    <h3 className="text-xl font-bold text-foreground mb-2 line-clamp-1">
                        {project.publicTitle || project.name || '-'}
                    </h3>

                    <div className="flex items-center gap-2 text-muted-foreground text-sm mb-4">
                        <Users className="w-4 h-4" />
                        <span className="truncate">
                            {project.client?.company || project.client?.name || 'Müşteri Yok'}
                        </span>
                    </div>
                </div>

                {/* Footer Info */}
                <div className="mt-auto pt-4 border-t border-border/50 flex justify-between items-center">
                    <div className="flex gap-2">
                        <span className={cn("px-2 py-1 rounded-md text-xs font-bold border", statusConfig[project.status]?.color)}>
                            {statusConfig[project.status]?.label}
                        </span>
                    </div>
                    <Link
                        href={`/admin/projects/edit/${project.id}`}
                        className="text-sm font-medium text-emerald-500 hover:underline"
                    >
                        Düzenle
                    </Link>
                </div>
            </div>
        )
    }

    return (
        <tr ref={setNodeRef} style={style} className="group hover:bg-muted/30 transition-colors bg-card">
            <td className="p-4 w-10">
                <button className="cursor-grab active:cursor-grabbing p-2 text-slate-400 hover:text-foreground" {...attributes} {...listeners}>
                    <GripVertical className="w-4 h-4" />
                </button>
            </td>
            <td className="p-4 pl-2">
                <div className="font-bold text-foreground text-sm">{project.internalName || project.name}</div>
                <div className="text-xs text-slate-500">{project.publicTitle}</div>
            </td>
            <td className="p-4 text-muted-foreground text-sm">
                {project.client?.company || project.client?.name || '-'}
            </td>
            <td className="p-4 font-mono text-sm">
                {formatCurrency(project.budget)}
            </td>
            <td className="p-4">
                <span className={cn("inline-flex items-center px-2.5 py-1 rounded-full text-xs font-bold border", statusConfig[project.status]?.color)}>
                    {statusConfig[project.status]?.label}
                </span>
            </td>
            <td className="p-4 text-right">
                <div className="flex items-center justify-end gap-2">
                    <Link href={`/admin/projects/edit/${project.id}`}>
                        <Button variant="ghost" size="icon" title="Düzenle">
                            <MoreHorizontal className="w-4 h-4" />
                        </Button>
                    </Link>
                    <Button
                        variant="ghost"
                        size="icon"
                        onClick={() => handleDelete(project.id)}
                        className="text-red-500 hover:text-red-400 hover:bg-red-500/10"
                        title="Sil"
                    >
                        <Trash2 className="w-4 h-4" />
                    </Button>
                </div>
            </td>
        </tr>
    )
}

export default function ProjectsPage() {
    const [projects, setProjects] = useState<Project[]>([])
    const [loading, setLoading] = useState(true)
    const [searchTerm, setSearchTerm] = useState("")
    const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid')
    const [isOrderChanged, setIsOrderChanged] = useState(false)
    const [savingOrder, setSavingOrder] = useState(false)

    const [selectedStatus, setSelectedStatus] = useState("all")
    const [selectedCategory, setSelectedCategory] = useState("all")
    const [categories, setCategories] = useState<string[]>([])

    // DND Sensors
    const sensors = useSensors(
        useSensor(PointerSensor),
        useSensor(KeyboardSensor, {
            coordinateGetter: sortableKeyboardCoordinates,
        })
    );

    useEffect(() => {
        fetchProjects()
    }, [])

    const fetchProjects = async () => {
        try {
            const res = await fetch('/api/projects')
            const data = await res.json()
            if (Array.isArray(data)) {
                setProjects(data)
                // Extract categories
                const cats = new Set<string>()
                data.forEach((p: any) => {
                    if (p.categories && Array.isArray(p.categories)) {
                        p.categories.forEach((c: string) => cats.add(c))
                    } else if (p.category) {
                        cats.add(p.category)
                    }
                })
                setCategories(Array.from(cats))
            }
        } catch (error) {
            console.error('Fetch error:', error)
        } finally {
            setLoading(false)
        }
    }

    const handleDragEnd = (event: DragEndEvent) => {
        const { active, over } = event;

        if (over && active.id !== over.id) {
            setProjects((items) => {
                const oldIndex = items.findIndex((item) => item.id === active.id);
                const newIndex = items.findIndex((item) => item.id === over.id);
                return arrayMove(items, oldIndex, newIndex);
            });
            setIsOrderChanged(true)
        }
    };

    const saveOrder = async () => {
        setSavingOrder(true)
        try {
            const orderData = projects.map((p, index) => ({
                id: p.id,
                order: index
            }))

            const res = await fetch('/api/projects/reorder', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ projects: orderData })
            })

            if (res.ok) {
                setIsOrderChanged(false)
                alert("Sıralama kaydedildi!")
            } else {
                throw new Error("Kaydedilemedi")
            }
        } catch (error) {
            alert("Sıralama kaydedilirken hata oluştu.")
        } finally {
            setSavingOrder(false)
        }
    }

    const handleDelete = async (id: number) => {
        if (!confirm('Bu projeyi silmek istediğinize emin misiniz?')) return
        try {
            const res = await fetch(`/api/projects?id=${id}`, { method: 'DELETE' })
            if (res.ok) setProjects(projects.filter(p => p.id !== id))
        } catch (error) {
            alert('Silme hatası')
        }
    }

    const formatCurrency = (amount: number) => {
        if (!amount) return '-'
        return new Intl.NumberFormat('tr-TR', { style: 'currency', currency: 'TRY', minimumFractionDigits: 0 }).format(amount)
    }

    const filteredProjects = projects.filter(project => {
        const search = searchTerm.toLowerCase()
        const matchesSearch = (
            (project.internalName?.toLowerCase().includes(search)) ||
            (project.publicTitle?.toLowerCase().includes(search)) ||
            (project.name?.toLowerCase().includes(search))
        )

        const matchesStatus = selectedStatus === 'all' || project.status === selectedStatus

        let matchesCategory = true
        if (selectedCategory !== 'all') {
            const pCats = (project as any).categories || []
            const pCat = (project as any).category
            if (Array.isArray(pCats) && pCats.length > 0) {
                matchesCategory = pCats.includes(selectedCategory)
            } else {
                matchesCategory = pCat === selectedCategory
            }
        }

        return matchesSearch && matchesStatus && matchesCategory
    })

    const statusConfig: any = {
        completed: { color: 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20', label: 'Tamamlandı', icon: '✅' },
        in_progress: { color: 'bg-blue-500/10 text-blue-400 border-blue-500/20', label: 'Devam Ediyor', icon: '🚀' },
        quote: { color: 'bg-yellow-500/10 text-yellow-400 border-yellow-500/20', label: 'Teklif', icon: '📝' },
        cancelled: { color: 'bg-slate-700/50 text-muted-foreground border-border', label: 'İptal', icon: '❌' },
    }

    if (loading) return <div className="p-20 text-center">Yükleniyor...</div>

    return (
        <div className="p-8 max-w-7xl mx-auto space-y-8">
            {/* Header */}
            <div className="flex flex-col lg:flex-row items-center justify-between gap-6">
                <div>
                    <h1 className="text-3xl font-bold flex items-center gap-3">
                        <Briefcase className="w-8 h-8 text-emerald-500" />
                        Projeler
                    </h1>
                    <p className="text-muted-foreground mt-2">Dilediğiniz gibi sürükleyip sıralayın.</p>
                </div>
                <div className="flex gap-3">
                    {isOrderChanged && (
                        <Button
                            onClick={saveOrder}
                            disabled={savingOrder}
                            className="font-bold flex items-center gap-2 animate-pulse"
                            variant="secondary"
                            size="lg"
                        >
                            <Save className="w-5 h-5 mr-1" />
                            {savingOrder ? 'Kaydediliyor...' : 'Sıralamayı Kaydet'}
                        </Button>
                    )}
                    <Link href="/admin/projects/new">
                        <Button size="lg">
                            <Plus className="w-5 h-5 mr-2" />
                            Yeni Proje
                        </Button>
                    </Link>
                </div>
            </div>

            {/* Filter Bar */}
            <Card className="p-4 rounded-xl border border-border shadow-sm flex flex-col md:flex-row gap-4 mb-6">
                <div className="relative flex-1">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                    <Input
                        type="text"
                        placeholder="Ara..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="pl-9"
                    />
                </div>

                <div className="flex gap-2 w-full md:w-auto overflow-x-auto">
                    {/* Status Filter */}
                    <Select value={selectedStatus} onValueChange={setSelectedStatus}>
                        <SelectTrigger className="w-[180px]">
                            <SelectValue placeholder="Tüm Durumlar" />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="all">Tüm Durumlar</SelectItem>
                            <SelectItem value="completed">Tamamlandı</SelectItem>
                            <SelectItem value="in_progress">Devam Ediyor</SelectItem>
                            <SelectItem value="quote">Teklif</SelectItem>
                            <SelectItem value="cancelled">İptal</SelectItem>
                        </SelectContent>
                    </Select>

                    {/* Category Filter */}
                    <Select value={selectedCategory} onValueChange={setSelectedCategory}>
                        <SelectTrigger className="w-[180px]">
                            <SelectValue placeholder="Tüm Kategoriler" />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="all">Tüm Kategoriler</SelectItem>
                            {categories.map(cat => (
                                <SelectItem key={cat} value={cat}>{cat}</SelectItem>
                            ))}
                        </SelectContent>
                    </Select>

                    <div className="flex bg-muted rounded-md border border-border shrink-0">
                        <Button variant={viewMode === 'grid' ? 'secondary' : 'ghost'} size="icon" onClick={() => setViewMode('grid')}>
                            <LayoutGrid className="w-4 h-4" />
                        </Button>
                        <Button variant={viewMode === 'list' ? 'secondary' : 'ghost'} size="icon" onClick={() => setViewMode('list')}>
                            <ListIcon className="w-4 h-4" />
                        </Button>
                    </div>
                </div>
            </Card>

            {/* Content */}
            <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
                <SortableContext items={filteredProjects.map(p => p.id)} strategy={verticalListSortingStrategy}>
                    {viewMode === 'grid' ? (
                        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
                            {filteredProjects.map(project => (
                                <SortableProjectItem
                                    key={project.id}
                                    project={project}
                                    viewMode="grid"
                                    statusConfig={statusConfig}
                                    formatCurrency={formatCurrency}
                                    handleDelete={handleDelete}
                                />
                            ))}
                        </div>
                    ) : (
                        <div className="bg-card border border-border rounded-3xl overflow-hidden">
                            <table className="w-full text-left">
                                <tbody className="divide-y divide-border">
                                    {filteredProjects.map(project => (
                                        <SortableProjectItem
                                            key={project.id}
                                            project={project}
                                            viewMode="list"
                                            statusConfig={statusConfig}
                                            formatCurrency={formatCurrency}
                                            handleDelete={handleDelete}
                                        />
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    )}
                </SortableContext>
            </DndContext>
        </div>
    )
}

"use client"

import { useState, useEffect } from "react"
import { Building2, MessageSquare, Plus, Edit, Trash2, ArrowUp, ArrowDown, Save, X, Check, Loader2, Star, Quote } from "lucide-react"
import ImageUploader from "@/components/admin/ImageUploader"

interface Client {
    id: number
    name: string
    company: string
    logo_url: string
    order: number
}

interface Testimonial {
    id: number
    author: string
    role: string
    company: string
    content: string
    avatarUrl: string
    rating: number
    order: number
    isActive: boolean
}

export default function ReferencesPage() {
    const [activeTab, setActiveTab] = useState<'brands' | 'testimonials'>('brands')

    // Data States
    const [clients, setClients] = useState<Client[]>([])
    const [testimonials, setTestimonials] = useState<Testimonial[]>([])
    const [loading, setLoading] = useState(true)

    // Edit/Create States
    const [isEditing, setIsEditing] = useState(false)
    const [editItem, setEditItem] = useState<any>(null) // For testimonial form

    useEffect(() => {
        loadData()
    }, [])

    const loadData = async () => {
        setLoading(true)
        try {
            const [clientsRes, testimonialsRes] = await Promise.all([
                fetch('/api/clients'),
                fetch('/api/testimonials')
            ])

            const clientsData = await clientsRes.json()
            const testimonialsData = await testimonialsRes.json()

            // Sort clients client-side as fallback
            const sortedClients = Array.isArray(clientsData) ? clientsData.sort((a: any, b: any) => (a.order || 0) - (b.order || 0)) : []
            setClients(sortedClients)
            setTestimonials(Array.isArray(testimonialsData) ? testimonialsData : [])

        } catch (error) {
            console.error('Failed to load data:', error)
        } finally {
            setLoading(false)
        }
    }

    // --- Brand Ordering Logic ---
    const moveClient = async (index: number, direction: 'up' | 'down') => {
        const newClients = [...clients]
        const targetIndex = direction === 'up' ? index - 1 : index + 1

        if (targetIndex < 0 || targetIndex >= newClients.length) return;

        // Swap items
        [newClients[index], newClients[targetIndex]] = [newClients[targetIndex], newClients[index]]

        // Update 'order' property
        const updatedClients = newClients.map((client, idx) => ({ ...client, order: idx }))
        setClients(updatedClients)

        // Save order to server
        try {
            await fetch('/api/clients/reorder', {
                method: 'POST',
                body: JSON.stringify({ items: updatedClients.map(c => ({ id: c.id, order: c.order })) })
            })
        } catch (error) {
            console.error('Failed to save order:', error)
            alert('Sıralama kaydedilemedi!')
        }
    }

    // --- Testimonial CRUD Logic ---
    const handleSaveTestimonial = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!editItem) return

        try {
            const url = editItem.id ? `/api/testimonials/${editItem.id}` : '/api/testimonials'
            const method = editItem.id ? 'PUT' : 'POST'

            const res = await fetch(url, {
                method,
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(editItem)
            })

            if (!res.ok) throw new Error('Failed to save')

            setIsEditing(false)
            setEditItem(null)
            loadData()
        } catch (error) {
            alert('Hata oluştu!')
        }
    }

    const handleDeleteTestimonial = async (id: number) => {
        if (!confirm('Silmek istediğinize emin misiniz?')) return
        try {
            await fetch(`/api/testimonials/${id}`, { method: 'DELETE' })
            loadData()
        } catch (error) {
            alert('Silinemedi!')
        }
    }

    // --- Render ---
    return (
        <div className="p-8 max-w-7xl mx-auto">
            <div className="flex items-center justify-between mb-8">
                <div>
                    <h1 className="text-3xl font-bold text-foreground">Referanslar & Yorumlar</h1>
                    <p className="text-muted-foreground">Marka sıralaması ve müşteri yorumlarını yönetin.</p>
                </div>
            </div>

            {/* Tabs */}
            <div className="flex gap-4 mb-8 border-b border-border">
                <button
                    onClick={() => setActiveTab('brands')}
                    className={`pb-4 px-4 font-medium transition-colors relative ${activeTab === 'brands' ? 'text-emerald-500' : 'text-muted-foreground hover:text-foreground'}`}
                >
                    <Building2 className="w-5 h-5 inline-block mr-2" />
                    Markalar
                    {activeTab === 'brands' && <span className="absolute bottom-0 left-0 w-full h-0.5 bg-emerald-500 rounded-t-full" />}
                </button>
                <button
                    onClick={() => setActiveTab('testimonials')}
                    className={`pb-4 px-4 font-medium transition-colors relative ${activeTab === 'testimonials' ? 'text-emerald-500' : 'text-muted-foreground hover:text-foreground'}`}
                >
                    <MessageSquare className="w-5 h-5 inline-block mr-2" />
                    Müşteri Yorumları
                    {activeTab === 'testimonials' && <span className="absolute bottom-0 left-0 w-full h-0.5 bg-emerald-500 rounded-t-full" />}
                </button>
            </div>

            {loading ? (
                <div className="flex justify-center py-20">
                    <Loader2 className="w-10 h-10 text-emerald-500 animate-spin" />
                </div>
            ) : (
                <>
                    {/* --- BRANDS TAB --- */}
                    {activeTab === 'brands' && (
                        <div>
                            <div className="bg-emerald-900/10 border border-emerald-900/20 text-emerald-400 p-4 rounded-xl mb-6 text-sm flex items-start gap-3">
                                <ArrowUp className="w-5 h-5 shrink-0" />
                                <div>
                                    <p className="font-bold">Nasıl Sıralanır?</p>
                                    <p>Markaları yukarı/aşağı butonlarını kullanarak sıralayabilirsiniz. Değişiklikler anında kaydedilir.</p>
                                </div>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                                {clients.map((client, index) => (
                                    <div key={client.id} className="bg-card border border-border p-4 rounded-xl flex items-center justify-between group hover:border-emerald-500/30 transition-colors">
                                        <div className="flex items-center gap-4">
                                            <span className="w-8 h-8 rounded-full bg-muted flex items-center justify-center text-sm font-bold text-muted-foreground">
                                                {index + 1}
                                            </span>
                                            {client.logo_url ? (
                                                <img src={client.logo_url} alt={client.name} className="h-10 w-24 object-contain" />
                                            ) : (
                                                <span className="font-bold text-foreground">{client.company || client.name}</span>
                                            )}
                                        </div>
                                        <div className="flex gap-1">
                                            <button
                                                onClick={() => moveClient(index, 'up')}
                                                disabled={index === 0}
                                                className="p-2 hover:bg-muted rounded-lg disabled:opacity-30 disabled:cursor-not-allowed text-muted-foreground hover:text-foreground"
                                            >
                                                <ArrowUp className="w-4 h-4" />
                                            </button>
                                            <button
                                                onClick={() => moveClient(index, 'down')}
                                                disabled={index === clients.length - 1}
                                                className="p-2 hover:bg-muted rounded-lg disabled:opacity-30 disabled:cursor-not-allowed text-muted-foreground hover:text-foreground"
                                            >
                                                <ArrowDown className="w-4 h-4" />
                                            </button>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}

                    {/* --- TESTIMONIALS TAB --- */}
                    {activeTab === 'testimonials' && (
                        <div>
                            {!isEditing ? (
                                <>
                                    <div className="flex justify-end mb-6">
                                        <button
                                            onClick={() => {
                                                setEditItem({ author: '', role: '', company: '', content: '', rating: 5, avatarUrl: '' })
                                                setIsEditing(true)
                                            }}
                                            className="bg-emerald-500 text-white px-4 py-2 rounded-lg font-bold hover:bg-emerald-600 transition-colors flex items-center gap-2"
                                        >
                                            <Plus className="w-4 h-4" /> Yeni Yorum Ekle
                                        </button>
                                    </div>

                                    <div className="grid md:grid-cols-2 gap-6">
                                        {testimonials.map(testimonial => (
                                            <div key={testimonial.id} className="bg-card border border-border p-6 rounded-xl relative group">
                                                <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                                    <button
                                                        onClick={() => {
                                                            setEditItem(testimonial)
                                                            setIsEditing(true)
                                                        }}
                                                        className="p-2 bg-muted rounded-lg hover:bg-emerald-500 hover:text-white transition-colors"
                                                    >
                                                        <Edit className="w-4 h-4" />
                                                    </button>
                                                    <button
                                                        onClick={() => handleDeleteTestimonial(testimonial.id)}
                                                        className="p-2 bg-muted rounded-lg hover:bg-red-500 hover:text-white transition-colors"
                                                    >
                                                        <Trash2 className="w-4 h-4" />
                                                    </button>
                                                </div>

                                                <div className="flex items-start gap-4 mb-4">
                                                    {testimonial.avatarUrl ? (
                                                        <img src={testimonial.avatarUrl} alt={testimonial.author} className="w-12 h-12 rounded-full object-cover" />
                                                    ) : (
                                                        <div className="w-12 h-12 rounded-full bg-muted flex items-center justify-center text-muted-foreground font-bold text-xl">
                                                            {testimonial.author.charAt(0)}
                                                        </div>
                                                    )}
                                                    <div>
                                                        <h3 className="font-bold text-foreground">{testimonial.author}</h3>
                                                        <p className="text-sm text-emerald-500">{testimonial.role} {testimonial.company && `at ${testimonial.company}`}</p>
                                                    </div>
                                                </div>

                                                <div className="flex mb-3">
                                                    {[...Array(5)].map((_, i) => (
                                                        <Star key={i} className={`w-4 h-4 ${i < testimonial.rating ? 'text-yellow-500 fill-yellow-500' : 'text-slate-700'}`} />
                                                    ))}
                                                </div>

                                                <p className="text-muted-foreground italic">"{testimonial.content}"</p>
                                            </div>
                                        ))}
                                        {testimonials.length === 0 && (
                                            <div className="col-span-full text-center py-12 text-muted-foreground">
                                                Henüz müşteri yorumu eklenmemiş.
                                            </div>
                                        )}
                                    </div>
                                </>
                            ) : (
                                /* --- EDIT FORM --- */
                                <div className="max-w-2xl mx-auto bg-card border border-border p-8 rounded-xl">
                                    <div className="flex justify-between items-center mb-6">
                                        <h2 className="text-xl font-bold flex items-center gap-2">
                                            {editItem.id ? <Edit className="w-5 h-5" /> : <Plus className="w-5 h-5" />}
                                            {editItem.id ? 'Yorumu Düzenle' : 'Yeni Yorum Ekle'}
                                        </h2>
                                        <button
                                            onClick={() => setIsEditing(false)}
                                            className="p-2 hover:bg-muted rounded-full"
                                        >
                                            <X className="w-5 h-5" />
                                        </button>
                                    </div>

                                    <form onSubmit={handleSaveTestimonial} className="space-y-6">
                                        <div className="grid grid-cols-2 gap-4">
                                            <div>
                                                <label className="block text-sm font-medium mb-1 text-slate-400">Yazar Adı Soyadı</label>
                                                <input
                                                    type="text"
                                                    value={editItem.author}
                                                    onChange={e => setEditItem({ ...editItem, author: e.target.value })}
                                                    required
                                                    className="w-full bg-background border border-border rounded-lg px-4 py-2"
                                                />
                                            </div>
                                            <div>
                                                <label className="block text-sm font-medium mb-1 text-slate-400">Unvan (Role)</label>
                                                <input
                                                    type="text"
                                                    value={editItem.role || ''}
                                                    onChange={e => setEditItem({ ...editItem, role: e.target.value })}
                                                    className="w-full bg-background border border-border rounded-lg px-4 py-2"
                                                />
                                            </div>
                                        </div>

                                        <div className="grid grid-cols-2 gap-4">
                                            <div>
                                                <label className="block text-sm font-medium mb-1 text-slate-400">Şirket</label>
                                                <input
                                                    type="text"
                                                    value={editItem.company || ''}
                                                    onChange={e => setEditItem({ ...editItem, company: e.target.value })}
                                                    className="w-full bg-background border border-border rounded-lg px-4 py-2"
                                                />
                                            </div>
                                            <div>
                                                <label className="block text-sm font-medium mb-1 text-slate-400">Puan (1-5)</label>
                                                <select
                                                    value={editItem.rating}
                                                    onChange={e => setEditItem({ ...editItem, rating: parseInt(e.target.value) })}
                                                    className="w-full bg-background border border-border rounded-lg px-4 py-2"
                                                >
                                                    {[5, 4, 3, 2, 1].map(r => (
                                                        <option key={r} value={r}>{r} Yıldız</option>
                                                    ))}
                                                </select>
                                            </div>
                                        </div>

                                        <div>
                                            <label className="block text-sm font-medium mb-1 text-slate-400">Yorum Metni</label>
                                            <textarea
                                                value={editItem.content}
                                                onChange={e => setEditItem({ ...editItem, content: e.target.value })}
                                                required
                                                rows={4}
                                                className="w-full bg-background border border-border rounded-lg px-4 py-2"
                                            />
                                        </div>

                                        <div>
                                            <label className="block text-sm font-medium mb-1 text-slate-400">Avatar Görseli</label>
                                            <ImageUploader
                                                value={editItem.avatarUrl}
                                                onChange={(url) => setEditItem({ ...editItem, avatarUrl: url })}
                                            />
                                        </div>

                                        <div className="flex justify-end gap-3 pt-4 border-t border-border">
                                            <button
                                                type="button"
                                                onClick={() => setIsEditing(false)}
                                                className="px-6 py-2 rounded-lg text-slate-400 hover:text-foreground font-medium"
                                            >
                                                İptal
                                            </button>
                                            <button
                                                type="submit"
                                                className="px-6 py-2 bg-emerald-500 text-white rounded-lg font-bold hover:bg-emerald-600 transition-colors flex items-center gap-2"
                                            >
                                                <Save className="w-4 h-4" /> Kaydet
                                            </button>
                                        </div>
                                    </form>
                                </div>
                            )}
                        </div>
                    )}
                </>
            )}
        </div>
    )
}

"use client"

import { useState, useEffect } from "react"
import { ArrowLeft, Save, Trash2, Layers, CheckCircle } from "lucide-react"
import Link from "next/link"
import { useRouter, useParams } from "next/navigation"

export default function EditServicePage() {
    const router = useRouter()
    const params = useParams()
    const { id } = params

    const [loading, setLoading] = useState(true)
    const [saving, setSaving] = useState(false)
    const [deleting, setDeleting] = useState(false)
    const [formData, setFormData] = useState<any>({
        title: "",
        slug: "",
        desc: "",
        icon: "Layers",
        status: "Aktif"
    })

    // Veriyi Getir
    useEffect(() => {
        // Tekil GET API olmadığı için tüm listeyi çekip filtreliyoruz (Geçici çözüm)
        // İdealde: /api/services?id=1 gibi olmalı
        const fetchData = async () => {
            try {
                const res = await fetch('/api/services')
                const data = await res.json()
                const service = data.find((item: any) => item.id == id)
                if (service) {
                    setFormData(service)
                } else {
                    alert("Hizmet bulunamadı!")
                    router.push('/admin/services')
                }
            } catch (error) {
                console.error("Veri çekme hatası:", error)
            } finally {
                setLoading(false)
            }
        }
        fetchData()
    }, [id, router])

    // Güncelle (PUT)
    const handleUpdate = async (e: React.FormEvent) => {
        e.preventDefault()
        setSaving(true)
        try {
            const res = await fetch('/api/services', {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(formData),
            })

            if (!res.ok) throw new Error('Güncellenemedi')

            alert("Hizmet başarıyla güncellendi!")
            router.push('/admin/services')
            router.refresh()
        } catch (error) {
            console.error(error)
            alert("Bir hata oluştu!")
        } finally {
            setSaving(false)
        }
    }

    // Sil (DELETE)
    const handleDelete = async () => {
        if (!confirm("Bu hizmeti silmek istediğinize emin misiniz?")) return

        setDeleting(true)
        try {
            const res = await fetch(`/api/services?id=${id}`, {
                method: 'DELETE',
            })

            if (!res.ok) throw new Error('Silinemedi')

            alert("Hizmet silindi.")
            router.push('/admin/services')
            router.refresh()
        } catch (error) {
            console.error(error)
            alert("Silme işlemi başarısız!")
        } finally {
            setDeleting(false)
        }
    }

    if (loading) return <div className="p-8 text-white">Yükleniyor...</div>

    return (
        <div className="p-8 max-w-4xl mx-auto space-y-8">
            {/* Header */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 border-b border-slate-800 pb-6">
                <div className="flex items-center gap-4">
                    <Link href="/admin/services" className="p-2 hover:bg-slate-900 rounded-lg text-slate-400 hover:text-white transition-colors">
                        <ArrowLeft className="w-5 h-5" />
                    </Link>
                    <div>
                        <h1 className="text-2xl font-bold text-white flex items-center gap-2">
                            <Layers className="w-6 h-6 text-emerald-500" />
                            Hizmeti Düzenle
                        </h1>
                        <p className="text-slate-400 text-sm">#{id} numaralı hizmet kaydını düzenliyorsunuz.</p>
                    </div>
                </div>
                <div className="flex gap-3">
                    <button
                        onClick={handleDelete}
                        disabled={deleting}
                        className="px-4 py-2 bg-red-500/10 hover:bg-red-500/20 text-red-500 rounded-xl font-bold transition-all border border-red-500/20 flex items-center gap-2"
                    >
                        <Trash2 className="w-4 h-4" /> {deleting ? 'Siliniyor...' : 'Sil'}
                    </button>
                    <button
                        onClick={handleUpdate}
                        disabled={saving}
                        className="px-6 py-2 bg-emerald-500 hover:bg-emerald-600 text-white rounded-xl font-bold transition-all shadow-lg shadow-emerald-500/20 flex items-center gap-2"
                    >
                        <Save className="w-4 h-4" /> {saving ? 'Kaydediliyor...' : 'Değişiklikleri Kaydet'}
                    </button>
                </div>
            </div>

            {/* Form */}
            <div className="grid md:grid-cols-2 gap-8">
                <div className="space-y-6">
                    <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 space-y-4">
                        <div>
                            <label className="block text-slate-400 text-sm font-medium mb-2">Hizmet Adı</label>
                            <input
                                type="text"
                                className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-emerald-500"
                                value={formData.title}
                                onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                            />
                        </div>
                        <div>
                            <label className="block text-slate-400 text-sm font-medium mb-2">Slug (URL)</label>
                            <input
                                type="text"
                                className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-slate-400 focus:outline-none focus:border-emerald-500"
                                value={formData.slug}
                                onChange={(e) => setFormData({ ...formData, slug: e.target.value })}
                            />
                        </div>
                    </div>

                    <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 space-y-4">
                        <div>
                            <label className="block text-slate-400 text-sm font-medium mb-2">Kısa Açıklama</label>
                            <textarea
                                className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-emerald-500 h-32 resize-none"
                                value={formData.desc}
                                onChange={(e) => setFormData({ ...formData, desc: e.target.value })}
                            />
                        </div>
                    </div>
                </div>

                <div className="space-y-6">
                    <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 space-y-4">
                        <label className="block text-slate-400 text-sm font-medium mb-2">Durum</label>
                        <select
                            className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-emerald-500"
                            value={formData.status}
                            onChange={(e) => setFormData({ ...formData, status: e.target.value })}
                        >
                            <option value="Aktif">Aktif</option>
                            <option value="Pasif">Pasif</option>
                            <option value="Beta">Beta</option>
                        </select>
                    </div>

                    <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 space-y-4">
                        <label className="block text-slate-400 text-sm font-medium mb-2">İkon Adı (Lucide React)</label>
                        <input
                            type="text"
                            className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-emerald-500"
                            placeholder="Örn: Globe, Monitor, Code"
                            value={formData.icon}
                            onChange={(e) => setFormData({ ...formData, icon: e.target.value })}
                        />
                        <p className="text-xs text-slate-500">Lucide ikon setinden bir isim girin.</p>
                    </div>
                </div>
            </div>
        </div>
    )
}

"use client"

export const dynamic = "force-dynamic"

import { useEffect, useState } from "react"
import { DndContext, DragOverlay, useDraggable, useDroppable, DragEndEvent, useSensors, useSensor, PointerSensor } from '@dnd-kit/core'
import { Plus, Clock, CheckCircle2, AlertCircle, X } from "lucide-react"
import { createPortal } from "react-dom"
import TaskDetailModal from "@/components/admin/tasks/TaskDetailModal"
import { useTeamWithCurrentUser } from "@/hooks/useTeamWithCurrentUser"

// --- Types ---
interface Task {
    id: number
    title: string
    description: string
    status: 'todo' | 'in_progress' | 'done'
    priority: 'low' | 'medium' | 'high'
    due_date?: string
    dueDate?: string // API response
    assigned_to?: any // Changed to any to support both String (userId) and Int (legacy)
    assignedTo?: any // API response
    userId?: string // New field
    project_id?: number
    projectId?: number // API response
    team_members?: { name: string }
    teamMember?: { name: string }
    user?: { name: string, image?: string, email?: string } // New relation
    projects?: { name: string }
    project?: { title: string, name: string } // API response
    checklists?: any[]
    labels?: any[]
}

const COLUMNS = [
    { id: 'todo', title: 'Yapılacaklar', color: 'bg-white0/10 border-slate-500/20 text-muted-foreground' },
    { id: 'in_progress', title: 'Sürüyor', color: 'bg-blue-500/10 border-blue-500/20 text-blue-400' },
    { id: 'done', title: 'Tamamlandı', color: 'bg-emerald-500/10 border-emerald-500/20 text-emerald-400' }
]

// --- Visual Component (Pure UI) ---
function TaskCardView({ task, team = [], isOverlay = false, onClick }: { task: Task, team?: any[], isOverlay?: boolean, onClick?: () => void }) {
    // Priority: user object -> userId -> assignedTo (legacy)
    const assignedId = task.userId || task.assignedTo || task.assigned_to
    // API user objesi dönüyor (image ile), team listesinde avatar_url olabilir
    const assignedUser = task.user || team.find((m: any) => m.id == assignedId)

    // API projectId dönüyor olabilir
    const projectId = task.projectId || task.project_id
    const projectTitle = task.project?.title || task.project?.name || task.projects?.name

    const priorityColor = {
        low: 'bg-muted text-foreground',
        medium: 'bg-yellow-500/10 text-yellow-500',
        high: 'bg-red-500/10 text-red-500'
    }[task.priority || 'medium']

    const checklistCount = task.checklists?.length || 0
    const completedChecklist = task.checklists?.filter((i: any) => i.checked).length || 0

    return (
        <div
            onClick={onClick}
            className={`bg-card border border-border p-4 rounded-xl cursor-grab active:cursor-grabbing hover:border-border transition-colors shadow-sm group ${isOverlay ? 'rotate-2 scale-105 shadow-xl border-emerald-500/50 z-50 cursor-grabbing' : ''}`}
        >
            <div className="flex justify-between items-start mb-2">
                <span className={`text-xs px-2 py-0.5 rounded font-medium ${priorityColor}`}>
                    {task.priority === 'high' ? 'Yüksek' : task.priority === 'medium' ? 'Orta' : 'Düşük'}
                </span>
                {(task.dueDate || task.due_date) && (
                    <span className="text-xs text-muted-foreground flex items-center gap-1">
                        <Clock className="w-3 h-3" />
                        {new Date(task.dueDate || task.due_date || '').toLocaleDateString('tr-TR', { day: 'numeric', month: 'short' })}
                    </span>
                )}
            </div>

            {projectTitle && (
                <div className="text-[10px] text-muted-foreground bg-muted rounded px-2 py-1 mb-2 inline-block max-w-full truncate border border-border/50">
                    📁 {projectTitle}
                </div>
            )}

            <h4 className="font-bold text-foreground mb-2 group-hover:text-emerald-400 transition-colors">{task.title}</h4>

            <div className="flex items-center gap-4 text-muted-foreground text-xs mt-3">
                <div className="flex items-center gap-1.5">
                    <div className="w-6 h-6 rounded-full bg-muted flex items-center justify-center text-[10px] font-bold text-foreground border border-border overflow-hidden ring-1 ring-border">
                        {assignedUser?.image || assignedUser?.avatar_url ? (
                            <img src={assignedUser.image || assignedUser.avatar_url} alt={assignedUser.name} className="w-full h-full object-cover" />
                        ) : (
                            assignedUser?.name?.[0]?.toUpperCase() || '?'
                        )}
                    </div>
                </div>

                {checklistCount > 0 && (
                    <div className={`flex items-center gap-1 ${completedChecklist === checklistCount ? 'text-emerald-500' : ''}`}>
                        <CheckCircle2 className="w-3.5 h-3.5" />
                        <span>{completedChecklist}/{checklistCount}</span>
                    </div>
                )}
            </div>
        </div>
    )
}

// --- Draggable Wrapper ---
function DraggableTaskCard({ task, team, onClick }: { task: Task, team: any[], onClick: () => void }) {
    const { attributes, listeners, setNodeRef, transform, isDragging } = useDraggable({
        id: task.id.toString(),
        data: task
    })

    const style = transform ? {
        transform: `translate3d(${transform.x}px, ${transform.y}px, 0)`,
    } : undefined

    if (isDragging) {
        return (
            <div ref={setNodeRef} style={style} className="opacity-50">
                <TaskCardView task={task} team={team} />
            </div>
        )
    }

    return (
        <div ref={setNodeRef} style={style} {...listeners} {...attributes}>
            <TaskCardView task={task} team={team} onClick={onClick} />
        </div>
    )
}

// --- Column Component ---
function KanbanColumn({ id, title, tasks, team, color, onTaskClick }: { id: string, title: string, tasks: Task[], team: any[], color: string, onTaskClick: (t: Task) => void }) {
    const { setNodeRef } = useDroppable({ id })

    return (
        <div ref={setNodeRef} className="flex flex-col h-full bg-white dark:bg-slate-900 rounded-notebook p-5 border border-border min-h-[500px] shadow-sm">
            <div className={`flex items-center justify-between border-b border-border pb-3 mb-4 ${color.replace('bg-', 'text-')}`}>
                <h3 className="font-bold flex items-center gap-2">
                    {id === 'todo' && <AlertCircle className="w-5 h-5" />}
                    {id === 'in_progress' && <Clock className="w-5 h-5" />}
                    {id === 'done' && <CheckCircle2 className="w-5 h-5" />}
                    {title}
                </h3>
                <span className={`text-xs px-2 py-1 rounded-full ${color.split(' ')[0]} ${color.split(' ')[2]}`}>
                    {tasks.length}
                </span>
            </div>
            <div className="space-y-3 flex-1">
                {tasks.map(task => (
                    <DraggableTaskCard key={task.id} task={task} team={team} onClick={() => onTaskClick(task)} />
                ))}
            </div>
        </div>
    )
}

// --- Main Page ---

export default function TasksPage() {
    const [tasks, setTasks] = useState<Task[]>([])
    const { team } = useTeamWithCurrentUser()
    const [projects, setProjects] = useState<any[]>([])
    const [selectedProjectId, setSelectedProjectId] = useState<string>("")
    const [activeId, setActiveId] = useState<string | null>(null)
    const [showModal, setShowModal] = useState(false)
    const [selectedTaskId, setSelectedTaskId] = useState<number | null>(null)
    const [mounted, setMounted] = useState(false)

    const sensors = useSensors(
        useSensor(PointerSensor, {
            activationConstraint: {
                distance: 8,
            },
        })
    )

    const [formData, setFormData] = useState<any>({
        title: '',
        description: '',
        status: 'todo',
        priority: 'medium',
        assigned_to: '',
        project_id: '',
        due_date: ''
    })

    useEffect(() => {
        setMounted(true)
        fetchTasks()
        fetchProjects()

        // LocalStorage değişikliklerini dinle
        const handleTasksUpdate = () => {
            console.log('🔄 Tasks updated event received, refreshing...')
            fetchTasks()
        }

        if (typeof window !== 'undefined') {
            window.addEventListener('tasks-updated', handleTasksUpdate)
        }

        return () => {
            if (typeof window !== 'undefined') {
                window.removeEventListener('tasks-updated', handleTasksUpdate)
            }
        }
    }, [])

    const fetchTasks = () => fetch('/api/tasks')
        .then(r => r.json())
        .then(data => {
            if (Array.isArray(data) && data.length > 0) {
                setTasks(data)
            } else if (process.env.NODE_ENV === 'development') {
                console.log("⚠️ Dev Mode: Using Mock Tasks")
                // LocalStorage varsa oradan al, yoksa sabit mock data
                try {
                    const localTasks = localStorage.getItem('mock_tasks')
                    if (localTasks) setTasks(JSON.parse(localTasks))
                    else setTasks(require('@/lib/mock-data').MOCK_TASKS)
                } catch (e) {
                    setTasks(require('@/lib/mock-data').MOCK_TASKS)
                }
            } else {
                setTasks([])
            }
        })
        .catch(err => {
            console.error("Fetch error:", err)
            if (process.env.NODE_ENV === 'development') {
                setTasks(require('@/lib/mock-data').MOCK_TASKS)
            } else {
                setTasks([])
            }
        })


    const fetchProjects = () => fetch('/api/projects')
        .then(r => r.json())
        .then(data => {
            if (Array.isArray(data) && data.length > 0) setProjects(data)
            else if (process.env.NODE_ENV === 'development') setProjects(require('@/lib/mock-data').MOCK_PROJECTS)
            else setProjects([])
        })

    const handleDelete = async (id: number) => {
        if (!confirm('Bu görevi silmek istediğinize emin misiniz?')) return

        try {
            const res = await fetch(`/api/tasks?id=${id}`, { method: 'DELETE' })
            if (res.ok) {
                setSelectedTaskId(null)
                fetchTasks()
            } else {
                alert('Silinemedi. Lütfen tekrar deneyin.')
            }
        } catch (error) {
            console.error(error)
            alert('Hata oluştu.')
        }
    }

    const handleDragStart = (event: any) => {
        setActiveId(event.active.id)
    }

    const handleDragEnd = async (event: DragEndEvent) => {
        const { active, over } = event
        setActiveId(null)

        if (!over) return

        const taskId = parseInt(active.id as string)
        const newStatus = over.id as Task['status']
        const currentTask = tasks.find(t => t.id === taskId)

        if (currentTask && currentTask.status !== newStatus) {
            setTasks(tasks.map(t =>
                t.id === taskId ? { ...t, status: newStatus } : t
            ))

            await fetch('/api/tasks', {
                method: 'PUT',
                body: JSON.stringify({ id: taskId, status: newStatus })
            })
        }
    }

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()

        const payload = {
            ...formData,
            assigned_to: formData.assigned_to ? String(formData.assigned_to) : null,
            project_id: formData.project_id ? Number(formData.project_id) : null,
            due_date: formData.due_date || null
        }

        try {
            const res = await fetch('/api/tasks', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload)
            })

            if (res.ok) {
                setShowModal(false)
                fetchTasks()
                setFormData({
                    title: '',
                    description: '',
                    status: 'todo',
                    priority: 'medium',
                    assigned_to: '',
                    project_id: '',
                    due_date: ''
                })
            } else {
                const err = await res.json()
                alert(`Görev oluşturulamadı: ${err.error || 'Bilinmeyen hata'}`)
            }
        } catch (error) {
            console.error("Submit Error:", error)
            alert('Sunucu ile iletişim kurulamadı.')
        }
    }

    const activeTask = activeId ? tasks.find(t => t.id.toString() === activeId) : null
    const selectedTask = selectedTaskId ? tasks.find(t => t.id === selectedTaskId) : null

    const filteredTasks = selectedProjectId
        ? tasks.filter(t => (t.projectId || t.project_id) === Number(selectedProjectId))
        : tasks

    if (!mounted) return <div className="p-8 text-muted-foreground">Yükleniyor...</div>

    return (
        <div className="p-8 max-w-7xl mx-auto h-[calc(100vh-2rem)] flex flex-col">
            <div className="flex justify-between items-center mb-8">
                <div>
                    <h1 className="text-3xl font-bold text-foreground flex items-center gap-3">
                        <CheckCircle2 className="w-8 h-8 text-emerald-500" />
                        Görev Yönetimi
                    </h1>
                    <p className="text-muted-foreground mt-1">Ekip iş takibi ve süreç yönetimi.</p>
                </div>

                <div className="flex gap-3">
                    <select
                        className="bg-card border border-border text-foreground text-sm rounded-xl px-4 py-3 focus:outline-none focus:border-emerald-500 shadow-sm"
                        value={selectedProjectId}
                        onChange={(e) => setSelectedProjectId(e.target.value)}
                    >
                        <option value="">Tüm Projeler</option>
                        {projects.map(p => (
                            <option key={p.id} value={p.id}>{p.title || p.name}</option>
                        ))}
                    </select>

                    <button
                        onClick={() => {
                            setFormData({ title: '', description: '', status: 'todo', priority: 'medium', assigned_to: '', project_id: '', due_date: '' })
                            setShowModal(true)
                        }}
                        className="bg-emerald-500 hover:bg-emerald-600 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2 shadow-lg shadow-emerald-500/20 transition-all hover:scale-105"
                    >
                        <Plus className="w-5 h-5" />
                        Yeni Görev
                    </button>
                </div>
            </div>

            <DndContext sensors={sensors} onDragStart={handleDragStart} onDragEnd={handleDragEnd}>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6 flex-1 overflow-hidden">
                    {COLUMNS.map(col => (
                        <KanbanColumn
                            key={col.id}
                            id={col.id}
                            title={col.title}
                            color={col.color}
                            team={team}
                            tasks={filteredTasks.filter(t => t.status === col.id)}
                            onTaskClick={(task) => {
                                setSelectedTaskId(task.id)
                            }}
                        />
                    ))}
                </div>
                {createPortal(
                    <DragOverlay>
                        {activeTask ? <TaskCardView task={activeTask} team={team} isOverlay /> : null}
                    </DragOverlay>,
                    document.body
                )}
            </DndContext>

            {selectedTask && (
                <TaskDetailModal
                    task={selectedTask}
                    onClose={() => setSelectedTaskId(null)}
                    onUpdate={() => fetchTasks()}
                    onDelete={() => handleDelete(selectedTask.id)}
                    projects={projects}
                    team={team}
                />
            )}

            {showModal && (
                <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50 backdrop-blur-sm">
                    <div className="bg-card border border-border rounded-notebook p-6 w-full max-w-md shadow-2xl">
                        <div className="flex justify-between items-center mb-6 border-b border-border pb-4">
                            <h2 className="text-xl font-bold text-foreground">Yeni Görev Ekle</h2>
                            <button onClick={() => setShowModal(false)} className="text-muted-foreground hover:text-foreground transition-colors">
                                <X className="w-6 h-6" />
                            </button>
                        </div>
                        <form onSubmit={handleSubmit} className="space-y-4">
                            <div>
                                <label className="block text-sm font-bold text-foreground mb-1.5">Başlık</label>
                                <input
                                    type="text"
                                    required
                                    className="w-full bg-muted/30 border border-border rounded-xl p-3 text-foreground focus:outline-none focus:border-emerald-500 focus:ring-2 focus:ring-emerald-500/10 transition-all font-medium"
                                    placeholder="Görev başlığı..."
                                    value={formData.title}
                                    onChange={e => setFormData({ ...formData, title: e.target.value })}
                                />
                            </div>

                            <div>
                                <label className="block text-sm font-bold text-foreground mb-1.5">Proje</label>
                                <select
                                    className="w-full bg-muted/30 border border-border rounded-xl p-3 text-foreground focus:outline-none focus:border-emerald-500 focus:ring-2 focus:ring-emerald-500/10 transition-all cursor-pointer"
                                    value={formData.project_id}
                                    onChange={e => setFormData({ ...formData, project_id: e.target.value })}
                                >
                                    <option value="">Proje Yok (Genel)</option>
                                    {projects.map(p => (
                                        <option key={p.id} value={p.id}>{p.title}</option>
                                    ))}
                                </select>
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-bold text-foreground mb-1.5">Atanan Kişi</label>
                                    <select
                                        className="w-full bg-muted/30 border border-border rounded-xl p-3 text-foreground focus:outline-none focus:border-emerald-500 focus:ring-2 focus:ring-emerald-500/10 transition-all cursor-pointer"
                                        value={formData.assigned_to}
                                        onChange={e => setFormData({ ...formData, assigned_to: e.target.value })}
                                    >
                                        <option value="">Seçiniz</option>
                                        {team.map(m => (
                                            <option key={m.id} value={m.id}>{m.name}</option>
                                        ))}
                                    </select>
                                </div>
                                <div>
                                    <label className="block text-sm font-bold text-foreground mb-1.5">Öncelik</label>
                                    <select
                                        className="w-full bg-muted/30 border border-border rounded-xl p-3 text-foreground focus:outline-none focus:border-emerald-500 focus:ring-2 focus:ring-emerald-500/10 transition-all cursor-pointer"
                                        value={formData.priority}
                                        onChange={e => setFormData({ ...formData, priority: e.target.value })}
                                    >
                                        <option value="low">Düşük</option>
                                        <option value="medium">Orta</option>
                                        <option value="high">Yüksek</option>
                                    </select>
                                </div>
                            </div>
                            <div>
                                <label className="block text-sm font-bold text-foreground mb-1.5">Bitiş Tarihi</label>
                                <input
                                    type="date"
                                    className="w-full bg-muted/30 border border-border rounded-xl p-3 text-foreground focus:outline-none focus:border-emerald-500 focus:ring-2 focus:ring-emerald-500/10 transition-all"
                                    value={formData.due_date}
                                    onChange={e => setFormData({ ...formData, due_date: e.target.value })}
                                />
                            </div>
                            <div className="pt-4 border-t border-border mt-4">
                                <button
                                    type="submit"
                                    className="w-full bg-emerald-500 hover:bg-emerald-600 text-white font-bold py-3 rounded-xl transition-all shadow-lg shadow-emerald-500/20 active:scale-95 flex items-center justify-center gap-2"
                                >
                                    <Plus className="w-5 h-5" />
                                    Görevi Oluştur
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    )
}

"use client"

export const dynamic = "force-dynamic"

import { useState, useEffect } from "react"
import { UsersRound, UserPlus, Trash2, Mail, Lock } from "lucide-react"
import ImageUpload from "@/components/ImageUpload"

export default function TeamPage() {
    const [team, setTeam] = useState<any[]>([])
    const [showForm, setShowForm] = useState(false)
    const [loading, setLoading] = useState(false)
    const [selectedMember, setSelectedMember] = useState<any>(null) // Düzenleme için
    const [formData, setFormData] = useState({
        name: "",
        email: "",
        password: "",
        role: "user",
        avatar_url: ""
    })

    useEffect(() => {
        fetchTeam()
    }, [])

    const fetchTeam = async () => {
        try {
            const res = await fetch('/api/team')
            const data = await res.json()
            setTeam(Array.isArray(data) ? data : [])
        } catch (error) {
            console.error('Fetch error:', error)
            setTeam([])
        }
    }

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()
        setLoading(true)

        try {
            const method = selectedMember ? 'PUT' : 'POST'
            const body = selectedMember
                ? JSON.stringify({ id: selectedMember.id, ...formData })
                : JSON.stringify(formData)

            const res = await fetch('/api/team', {
                method,
                headers: { 'Content-Type': 'application/json' },
                body
            })

            const result = await res.json()

            if (!res.ok) throw new Error(result.error || 'İşlem başarısız')

            alert(selectedMember ? 'Kullanıcı güncellendi!' : 'Kullanıcı eklendi!')
            setShowForm(false)
            setSelectedMember(null)
            setFormData({ name: "", email: "", password: "", role: "user", avatar_url: "" })
            fetchTeam()
        } catch (error: any) {
            alert(error.message || 'Bir hata oluştu!')
        } finally {
            setLoading(false)
        }
    }

    const handleDelete = async (id: string) => {
        if (!confirm('Bu kullanıcıyı silmek istediğinize emin misiniz? Bu işlem geri alınamaz.')) return

        try {
            const res = await fetch(`/api/team?id=${id}`, { method: 'DELETE' })
            if (res.ok) {
                setTeam(team.filter(t => t.id !== id))
                alert('Kullanıcı silindi')
            } else {
                alert('Silme işlemi başarısız')
            }
        } catch (error) {
            alert('Silme hatası')
        }
    }

    const getRoleBadge = (role: string) => {
        const r = role?.toLowerCase()
        switch (r) {
            case 'admin': return 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20'
            case 'manager': return 'bg-blue-500/10 text-blue-400 border-blue-500/20'
            default: return 'bg-slate-700/50 text-muted-foreground border-border'
        }
    }

    const getRoleText = (role: string) => {
        const r = role?.toLowerCase()
        switch (r) {
            case 'admin': return 'Yönetici'
            case 'manager': return 'Müdür'
            default: return 'Kullanıcı'
        }
    }

    return (
        <div className="p-8 max-w-7xl mx-auto space-y-8">

            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-3xl font-bold text-foreground flex items-center gap-3">
                        <UsersRound className="w-8 h-8 text-emerald-500" />
                        Ekip Yönetimi
                    </h1>
                    <p className="text-muted-foreground mt-1">Sisteme giriş yapabilecek kullanıcıları yönetin</p>
                </div>
                <button
                    onClick={() => {
                        setShowForm(!showForm)
                        setSelectedMember(null)
                        setFormData({ name: "", email: "", password: "", role: "user", avatar_url: "" })
                    }}
                    className="px-6 py-3 bg-emerald-500 hover:bg-emerald-600 text-white rounded-xl font-bold transition-all shadow-lg shadow-emerald-500/20 flex items-center gap-2"
                >
                    <UserPlus className="w-5 h-5" />
                    {showForm ? 'Formu Gizle' : 'Kullanıcı Ekle'}
                </button>
            </div>

            {/* Form */}
            {showForm && (
                <form onSubmit={handleSubmit} className="bg-card border border-border rounded-notebook p-6 space-y-6">
                    <h2 className="text-lg font-bold text-foreground border-b border-border pb-3">
