import { NextRequest, NextResponse } from 'next/server'
import prisma from '@/lib/prisma'

// GET - Tüm blog yazılarını getir
export async function GET() {
    try {
        const posts = await prisma.post.findMany({
            orderBy: { createdAt: 'desc' }
        })

        return NextResponse.json(posts)
    } catch (error: unknown) {
        console.error('Posts GET error:', error)
        const message = error instanceof Error ? error.message : 'Unknown error'
        return NextResponse.json({ error: message }, { status: 500 })
    }
}

// POST - Yeni blog yazısı ekle
export async function POST(request: Request) {
    try {
        const body = await request.json()

        const slug = body.slug || body.title.toLowerCase()
            .replace(/ /g, '-')
            .replace(/[^\w-]+/g, '')
            .replace(/ğ/g, 'g')
            .replace(/ü/g, 'u')
            .replace(/ş/g, 's')
            .replace(/ı/g, 'i')
            .replace(/ö/g, 'o')
            .replace(/ç/g, 'c')

        const post = await prisma.post.create({
            data: {
                title: body.title,
                slug,
                content: body.content,
                excerpt: body.excerpt,
                category: body.category,
                image: body.image,
                status: body.status || 'published',
                readTime: body.readTime || '5 dk'
            }
        })

        return NextResponse.json(post)
    } catch (error: unknown) {
        console.error('Posts POST error:', error)
        const message = error instanceof Error ? error.message : 'Unknown error'
        return NextResponse.json({ error: message }, { status: 500 })
    }
}

// PUT - Blog yazısı güncelle
export async function PUT(request: Request) {
    try {
        const body = await request.json()
        const { id, ...updates } = body

        if (!id) {
            return NextResponse.json({ error: 'ID gerekli' }, { status: 400 })
        }

        const post = await prisma.post.update({
            where: { id: parseInt(id) },
            data: updates
        })

        return NextResponse.json(post)
    } catch (error: unknown) {
        console.error('Posts PUT error:', error)
        const message = error instanceof Error ? error.message : 'Unknown error'
        return NextResponse.json({ error: message }, { status: 500 })
    }
}

// DELETE - Blog yazısı sil
export async function DELETE(request: Request) {
    try {
        const { searchParams } = new URL(request.url)
        const id = searchParams.get('id')

        if (!id) {
            return NextResponse.json({ error: 'ID gerekli' }, { status: 400 })
        }

        await prisma.post.delete({
            where: { id: parseInt(id) }
        })

        return NextResponse.json({ success: true })
    } catch (error: unknown) {
        console.error('Posts DELETE error:', error)
        const message = error instanceof Error ? error.message : 'Unknown error'
        return NextResponse.json({ error: message }, { status: 500 })
    }
}

import { NextRequest, NextResponse } from 'next/server'
import prisma from '@/lib/prisma'

// GET - Tüm projeleri veya tek projeyi getir (ID varsa)
export async function GET(request: NextRequest) {
    try {
        const { searchParams } = new URL(request.url)
        const id = searchParams.get('id')

        if (id) {
            // Tekil proje detayı (Görevler ile birlikte)
            const project = await prisma.project.findUnique({
                where: { id: parseInt(id) },
                include: {
                    client: {
                        select: { id: true, name: true, company: true }
                    },
                    tasks: true
                }
            })

            if (!project) {
                return NextResponse.json({ error: 'Proje bulunamadı' }, { status: 404 })
            }

            return NextResponse.json(project)
        }

        const slug = searchParams.get('slug')
        if (slug) {
            const project = await prisma.project.findUnique({
                where: { slug },
                include: { client: true } // Include client for sidebar
            })
            if (!project) return NextResponse.json({ error: 'Proje bulunamadı' }, { status: 404 })
            return NextResponse.json(project)
        }

        const type = searchParams.get('type')

        // Liste
        const projects = await prisma.project.findMany({
            where: {
                ...(type ? { isLabProject: type === 'lab' } : {}) // Filter only if type is provided
            },
            include: {
                client: {
                    select: { id: true, name: true, company: true }
                }
            },
            orderBy: [
                { order: 'asc' },
                { createdAt: 'desc' }
            ]
        })

        return NextResponse.json(projects)
    } catch (error: unknown) {
        console.error('Projects GET error:', error)
        const message = error instanceof Error ? error.message : 'Unknown error'
        return NextResponse.json({ error: message }, { status: 500 })
    }
}

// POST - Yeni proje ekle
export async function POST(request: NextRequest) {
    try {
        const body = await request.json()

        // title/name senkronizasyonu
        const title = body.title || body.name
        const name = body.name || body.title

        // Generate base slug
        let baseSlug = body.slug || (body.publicTitle || body.name || '').toLowerCase()
            .replace(/ğ/g, 'g').replace(/ü/g, 'u').replace(/ş/g, 's')
            .replace(/ı/g, 'i').replace(/ö/g, 'o').replace(/ç/g, 'c')
            .replace(/[^a-z0-9-]/g, '-').replace(/-+/g, '-')
            .replace(/^-+|-+$/g, '') // Remove leading/trailing dashes

        // Vogo Labs suffix logic
        if (body.isLabProject && !baseSlug.endsWith('-lab')) {
            // Optional: Force -lab suffix or just ensure uniqueness?
            // User requested uniqueness check. 
        }

        // Ensure slug is unique
        let slug = baseSlug
        let counter = 1
        while (await prisma.project.findUnique({ where: { slug } })) {
            slug = `${baseSlug}-${counter}`
            counter++
        }

        const project = await prisma.project.create({
            data: {
                // New Fields
                internalName: body.internalName || body.name,
                publicTitle: body.publicTitle || body.title || body.name,
                slug: slug,
                content: body.content,
                order: body.order || 0,

                // Vogo Labs Fields
                isLabProject: body.isLabProject || false,
                thumbnail: body.thumbnail,
                liveUrl: body.liveUrl,
                tags: body.tags || [],

                // Premium Showcase Fields
                heroImage: body.heroImage,
                heroVideo: body.heroVideo,
                year: body.year,
                services: body.services || [],
                contentBlocks: body.contentBlocks || [],

                // Additional Metadata
                market: body.market,
                clientType: body.clientType,
                websiteUrl: body.websiteUrl,
                gallery: body.gallery || [],

                // Legacy / Shared
                title,
                name,
                description: body.description,
                status: body.status || 'in_progress',
                category: body.category,
                categories: body.categories || [],
                budget: body.budget ? parseFloat(body.budget) : null,
                startDate: body.startDate ? new Date(body.startDate) : null,
                endDate: body.endDate ? new Date(body.endDate) : null,
                priority: body.priority || 'medium',
                progress: body.progress || 0,
                image: body.image,
                clientId: body.clientId ? parseInt(body.clientId) : null,
            }
        })

        return NextResponse.json(project)
    } catch (error: unknown) {
        console.error('Projects POST error:', error)
        const message = error instanceof Error ? error.message : 'Unknown error'
        return NextResponse.json({ error: message }, { status: 500 })
    }
}

// PUT - Proje güncelle
export async function PUT(request: NextRequest) {
    try {
        const body = await request.json()
        const { id, ...updateData } = body

        // Explicitly select and validate known fields to prevent unknown argument errors
        const sanitizedData: any = {
            internalName: updateData.internalName || updateData.name,
            publicTitle: updateData.publicTitle || updateData.title || updateData.internalName || updateData.name,
            name: updateData.name || updateData.internalName, // legacy sync
            title: updateData.title || updateData.publicTitle || updateData.name, // legacy sync
            description: updateData.description,
            content: updateData.content,
            status: updateData.status,
            category: updateData.category,
            categories: updateData.categories,
            order: updateData.order,
            budget: updateData.budget ? parseFloat(updateData.budget) : undefined,
            startDate: updateData.startDate ? new Date(updateData.startDate) : (updateData.start_date ? new Date(updateData.start_date) : undefined),
            endDate: updateData.endDate ? new Date(updateData.endDate) : (updateData.end_date ? new Date(updateData.end_date) : undefined),
            priority: updateData.priority,
            heroImage: updateData.heroImage,
            year: updateData.year,
            services: updateData.services,
            market: updateData.market,
            clientType: updateData.clientType,
            websiteUrl: updateData.websiteUrl,
            gallery: updateData.gallery,
            image: updateData.image, // Featured/Card Image

            // Vogo Labs
            isLabProject: updateData.isLabProject,
            thumbnail: updateData.thumbnail,
            liveUrl: updateData.liveUrl,
            tags: updateData.tags,
            contentBlocks: updateData.contentBlocks,
        }

        // Clean up undefined values to avoid overwriting with null unless intended
        Object.keys(sanitizedData).forEach(key => {
            if (sanitizedData[key] === undefined) {
                delete sanitizedData[key]
            }
        })

        // Handle client relation separately
        if (updateData.client_id !== undefined || updateData.clientId !== undefined) {
            const cid = updateData.client_id ? parseInt(updateData.client_id) : (updateData.clientId ? parseInt(updateData.clientId) : null)
            if (cid) {
                sanitizedData.client = { connect: { id: cid } }
            } else {
                sanitizedData.client = { disconnect: true }
            }
        }

        const project = await prisma.project.update({
            where: { id: parseInt(id) },
            data: sanitizedData
        })

        return NextResponse.json(project)
    } catch (error: unknown) {
        console.error('Projects PUT error:', error)
        const message = error instanceof Error ? error.message : 'Unknown error'
        return NextResponse.json({ error: message }, { status: 500 })
    }
}

// DELETE - Proje sil
export async function DELETE(request: NextRequest) {
    try {
        const { searchParams } = new URL(request.url)
        const id = searchParams.get('id')

        if (!id) {
            return NextResponse.json({ error: 'ID gerekli' }, { status: 400 })
