                                </div>

                                {/* CTA Button */}
                                <Link href={`/services/${currentService.slug}`} className="block w-full">
                                    <motion.button
                                        initial={{ opacity: 0, y: 20 }}
                                        animate={{ opacity: 1, y: 0 }}
