                                <li key={i} className="flex gap-3 text-emerald-900 dark:text-emerald-200/80 text-sm font-medium">
                                    <span className="mt-1.5 w-1.5 h-1.5 rounded-full bg-emerald-600 dark:bg-emerald-500 shrink-0" />
