                        e.preventDefault();
                        const btn = e.currentTarget.querySelector('button');
                        if (btn) {
                            btn.textContent = 'Gönderildi!';
                            btn.classList.add('bg-green-500', 'text-white');
                            setTimeout(() => {
                                btn.textContent = 'Gönder';
                                btn.classList.remove('bg-green-500', 'text-white');
