                        alert("Rapor talebiniz alındı. Kısa süre içinde PDF olarak iletilecektir.");
                    }} className="flex gap-2">
                        <input required type="email" placeholder="ornek@sirket.com" className="flex-1 bg-white text-black border border-white/10 rounded-lg px-4 py-2 focus:ring-2 focus:ring-emerald-500 outline-none transition-all placeholder:text-zinc-500" />
                        <button type="submit" className="bg-white hover:bg-zinc-200 text-black px-6 py-2 rounded-lg font-bold transition-all min-w-[100px]">Gönder</button>
                    </form>
                </div>

                <div className="pt-6 border-t border-white/5 flex flex-col items-center gap-4">
                    <p className="text-zinc-400 text-sm">
                        Vogo Lab bu hataları <span className="text-emerald-400 font-bold">48 saat içinde</span> düzeltebilir.
                    </p>
                    <div className="flex gap-4 items-center justify-center">
                        <button onClick={onRetry} className="text-zinc-500 hover:text-white transition underline text-sm">Yeni Analiz Yap</button>
                        <span className="text-zinc-700">|</span>
                        <a href="/contact" className="text-emerald-500 hover:text-emerald-400 transition font-medium flex items-center gap-2">
                            Vogo Lab Uzmanına Danış
                            <ArrowRight className="w-4 h-4" />
                        </a>
                    </div>
                </div>
            </div>
        </motion.div>
    )
}

function ScoreCard({ title, score, icon, delay = 0 }: { title: string, score: number, icon: React.ReactNode, delay?: number }) {
    let color = "text-red-500"
    if (score >= 50) color = "text-yellow-500"
    if (score >= 80) color = "text-emerald-500"

    return (
        <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay, duration: 0.5 }}
            className="bg-card border border-border p-6 rounded-2xl flex flex-col items-center justify-center text-center gap-4 hover:border-emerald-500/30 transition-colors"
        >
            <div className="p-3 rounded-full bg-muted/50 text-muted-foreground">
                {icon}
            </div>
            <div>
                <div className={`text-4xl font-black mb-1 ${color}`}>
                    {score}
                </div>
                <div className="text-sm font-medium text-muted-foreground uppercase tracking-wider">
                    {title}
                </div>
            </div>
        </motion.div>
    )
}

"use client"

import { useRef } from "react"
import { motion, useScroll, useTransform, MotionValue } from "framer-motion"

interface ParallaxImageProps {
    src: string
    alt: string
    className?: string
    offset?: number
}

export default function ParallaxImage({ src, alt, className = "", offset = 50 }: ParallaxImageProps) {
    const ref = useRef(null)
    const { scrollYProgress } = useScroll({
        target: ref,
        offset: ["start end", "end start"]
    })

    const y = useTransform(scrollYProgress, [0, 1], [-offset, offset])
    const scale = useTransform(scrollYProgress, [0, 0.5, 1], [1.1, 1, 1.1]) // Subtle zoom too

    return (
        <div ref={ref} className={`overflow-hidden relative ${className}`}>
            <motion.img
                src={src}
                alt={alt}
                style={{ y, scale }}
                className="w-full h-full object-cover"
            />
        </div>
    )
}

import { useEffect, useState } from 'react'
import { useSession } from 'next-auth/react'

export interface TeamMember {
    id: string | number
    name: string
    email?: string
    role?: string
    avatar_url?: string // UI uses avatar_url
    active?: boolean
}

export function useTeamWithCurrentUser() {
    const [team, setTeam] = useState<TeamMember[]>([])
    const [loading, setLoading] = useState(true)
    const { data: session } = useSession()

    useEffect(() => {
        fetchTeamWithCurrentUser()
    }, [session])

    const fetchTeamWithCurrentUser = async () => {
        try {
            // 1. Team listesini al
            const res = await fetch('/api/team')
            if (!res.ok) throw new Error('Failed to fetch team')

            const data = await res.json()
            let teamList: TeamMember[] = Array.isArray(data) ? data : []

            // 2. Authenticated user'ı kontrol et ve gerekirse ekle (API henüz dönmediyse veya senkronizasyon sorunu varsa)
            if (session?.user?.email) {
                const userEmail = session.user.email
                // Email bazında kontrol et
                const userExists = teamList.some((m) => m.email === userEmail)

                if (!userExists) {
                    const currentUser: TeamMember = {
                        id: session.user.id || 'current-user',
                        name: session.user.name || userEmail.split('@')[0],
                        email: userEmail,
                        role: (session.user as any).role || 'user',
                        avatar_url: session.user.image || '',
                        active: true
                    }
                    // Listeye ekle
                    teamList = [currentUser, ...teamList]
                }
            }

            setTeam(teamList)
        } catch (err) {
            console.error("Team fetch error:", err)
            setTeam([]) // Mock data yerine boş liste dön
        } finally {
            setLoading(false)
        }
    }

    return { team, loading, refetch: fetchTeamWithCurrentUser }
}

import NextAuth from "next-auth"
import Credentials from "next-auth/providers/credentials"
import { PrismaAdapter } from "@auth/prisma-adapter"
import prisma from "@/lib/prisma"
import bcrypt from "bcryptjs"

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export const { handlers, signIn, signOut, auth } = NextAuth({
    adapter: PrismaAdapter(prisma) as any,
    session: {
        strategy: "jwt",
    },
    pages: {
        signIn: "/login",
    },
    providers: [
        Credentials({
            name: "Credentials",
            credentials: {
                email: { label: "Email", type: "email" },
                password: { label: "Password", type: "password" }
            },
            async authorize(credentials) {
                console.log("Login attempt for:", credentials?.email);

                if (!credentials?.email || !credentials?.password) {
                    console.log("Missing credentials");
                    return null
                }

                const user = await prisma.user.findUnique({
                    where: { email: credentials.email as string }
                })

                if (!user) {
                    console.log("User not found");
                    return null;
                }

                if (!user.password) {
                    console.log("User has no password set");
                    return null;
                }

                const isPasswordValid = await bcrypt.compare(
                    credentials.password as string,
                    user.password
                )

                if (!isPasswordValid) {
                    console.log("Password invalid");
                    return null
                }

                console.log("Login successful:", user.email);

                // Kullanıcı nesnesini döndür
                return {
                    id: user.id,
                    email: user.email,
                    name: user.name,
                    role: user.role,
                    image: user.image, // Avatar için önemli
                }
            }
        })
    ],
    callbacks: {
        async jwt({ token, user, trigger, session }) {
            // İlk login anı
            if (user) {
                token.id = user.id ?? ''
                token.role = (user as any).role
                token.picture = user.image
                token.name = user.name
            }

            // Session update tetiklenirse (örn: profil güncelleme)
            if (trigger === "update" && session) {
                token.name = session.name
                token.picture = session.image
            }

            return token
        },
        async session({ session, token }) {
            if (session.user) {
                session.user.id = token.id as string
                (session.user as any).role = token.role as string
                session.user.name = token.name as string
                session.user.image = token.picture as string
            }
            return session
        },
    },
})

